static inline float tvdiff_ms(const struct timeval *start, const struct timeval *end) {
    return (float)((end->tv_sec - start->tv_sec) * 1000.0 +
                   (end->tv_usec - start->tv_usec) / 1000.0);
}

static inline void cuda_check(cudaError_t err, const char *msg) {
    if (err != cudaSuccess) {
        printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
        fflush(NULL);
        exit(EXIT_FAILURE);
    }
}

extern "C" int device_id_inuse;
extern "C" int platform_id_inuse;

__global__ void findK(long height,
                      knode *knodesD,
                      long knodes_elem,
                      record *recordsD,
                      long *currKnodeD,
                      long *offsetD,
                      int *keysD,
                      record *ansD)
{
    int thid = threadIdx.x;
    int bid = blockIdx.x;

    for (int i = 0; i < height; i++) {
        if ((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] &&
            (knodesD[currKnodeD[bid]].keys[thid + 1] > keysD[bid])) {
            if (knodesD[offsetD[bid]].indices[thid] < knodes_elem) {
                offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
            }
        }

        __syncthreads();

        if (thid == 0) {
            currKnodeD[bid] = offsetD[bid];
        }

        __syncthreads();
    }

    if (knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]) {
        ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
    }
}

