static inline float tvdiff_ms_2(const struct timeval *start, const struct timeval *end) {
    return (float)((end->tv_sec - start->tv_sec) * 1000.0 +
                   (end->tv_usec - start->tv_usec) / 1000.0);
}

static inline void cuda_check_2(cudaError_t err, const char *msg) {
    if (err != cudaSuccess) {
        printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
        fflush(NULL);
        exit(EXIT_FAILURE);
    }
}

