#ifdef PROFILING
class timer {
public:
    timer(const char *name = 0) : name_(name ? name : "timer"), write_on_exit_(false) { reset(); }
    timer(const char *name, std::ostream &) : name_(name ? name : "timer"), write_on_exit_(true) { reset(); }
    ~timer() {}

    void start() { running_ = true; start_tp_ = std::chrono::high_resolution_clock::now(); }
    void stop() {
        if (running_) {
            total_time_sec_ += std::chrono::duration<double>(
                std::chrono::high_resolution_clock::now() - start_tp_).count();
            running_ = false;
            ++count_;
        }
    }
    void reset() {
        total_time_sec_ = 0.0;
        count_ = 0;
        running_ = false;
    }
    std::ostream &print(std::ostream &os) {
        os << std::left << std::setw(25) << name_ << ": " << std::right;
        if (count_ > 0) {
            os << "avg = " << (total_time_sec_ / static_cast<double>(count_))
               << " s, total = " << total_time_sec_
               << " s, count = " << count_ << '\n';
        } else {
            os << "not used\n";
        }
        return os;
    }
    double getTimeInSeconds() { return total_time_sec_; }

private:
    const char *name_;
    bool write_on_exit_;
    bool running_;
    unsigned long long count_;
    double total_time_sec_;
    std::chrono::high_resolution_clock::time_point start_tp_;
};

static inline std::ostream &operator<<(std::ostream &os, timer &t) {
