static void _clCmdParams(int argc, char* argv[]) {
    for (int i = 0; i < argc; ++i) {
        if (argv[i] == NULL || std::strlen(argv[i]) < 2 || argv[i][0] != '-') continue;
        switch (argv[i][1]) {
        case 'g':
            if (++i < argc) {
                std::sscanf(argv[i], "%u", &work_group_size);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("invalid command line");
            }
            break;
        case 'd':
            if (++i < argc) {
                std::sscanf(argv[i], "%u", &device_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("invalid command line");
            }
            break;
        case 'p':
            if (++i < argc) {
                std::sscanf(argv[i], "%u", &platform_id_inuse);
            } else {
                std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                throw std::string("invalid command line");
            }
            break;
        default:
            ;
        }
    }
}

static void _cudaInit() {
    int deviceCount = 0;
    checkCuda(cudaGetDeviceCount(&deviceCount), "cudaGetDeviceCount");
    printf("number of platforms:%d\n", 1);
    printf("vendor is %s\n", "NVIDIA Corporation");
    if (deviceCount <= 0) {
        throw std::string("InitCL()::Error: No devices found.");
    }
    std::cout << "device number: " << deviceCount << std::endl;
    if (device_id_inuse < 0 || device_id_inuse >= deviceCount) {
        throw std::string("invalid device id");
    }
    checkCuda(cudaSetDevice(device_id_inuse), "cudaSetDevice");
    checkCuda(cudaFree(0), "cudaFree(0)");
    printf("Creating GPU Context\n");
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref) {
    (void)edge_list_size;
    char stop;
    int k = 0;
    do {
        stop = false;
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting;
                     i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting);
                     i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost_ref[id] = h_cost_ref[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
        k++;
    } while (stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost) {
    char h_over = false;
    Node *d_graph_nodes = NULL;
    int *d_graph_edges = NULL;
    char *d_graph_mask = NULL;
    char *d_updating_graph_mask = NULL;
    char *d_graph_visited = NULL;
    int *d_cost = NULL;
    char *d_over = NULL;

    try {
#ifdef TIMING
        gettimeofday(&tv_total_start, NULL);
#endif

        _cudaInit();

#ifdef TIMING
        gettimeofday(&tv_mem_alloc_start, NULL);
        tvsub(&tv_mem_alloc_start, &tv_total_start, &tv);
        init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        checkCuda(cudaMalloc((void**)&d_graph_nodes, no_of_nodes * sizeof(Node)), "cudaMalloc d_graph_nodes");
        checkCuda(cudaMalloc((void**)&d_graph_edges, edge_list_size * sizeof(int)), "cudaMalloc d_graph_edges");
        checkCuda(cudaMalloc((void**)&d_graph_mask, no_of_nodes * sizeof(char)), "cudaMalloc d_graph_mask");
        checkCuda(cudaMalloc((void**)&d_updating_graph_mask, no_of_nodes * sizeof(char)), "cudaMalloc d_updating_graph_mask");
        checkCuda(cudaMalloc((void**)&d_graph_visited, no_of_nodes * sizeof(char)), "cudaMalloc d_graph_visited");
        checkCuda(cudaMalloc((void**)&d_cost, no_of_nodes * sizeof(int)), "cudaMalloc d_cost");
        checkCuda(cudaMalloc((void**)&d_over, sizeof(char)), "cudaMalloc d_over");

#ifdef TIMING
        gettimeofday(&tv_mem_alloc_end, NULL);
        tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
        mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

        gettimeofday(&tv_h2d_start, NULL);
#endif

        checkCuda(cudaMemcpy(d_graph_nodes, h_graph_nodes, no_of_nodes * sizeof(Node), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_graph_nodes");
        checkCuda(cudaMemcpy(d_graph_edges, h_graph_edges, edge_list_size * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_graph_edges");
        checkCuda(cudaMemcpy(d_graph_mask, h_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_graph_mask");
        checkCuda(cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_updating_graph_mask");
        checkCuda(cudaMemcpy(d_graph_visited, h_graph_visited, no_of_nodes * sizeof(char), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_graph_visited");
        checkCuda(cudaMemcpy(d_cost, h_cost, no_of_nodes * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_cost");

#ifdef TIMING
        gettimeofday(&tv_h2d_end, NULL);
        tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
        h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        int num_threads = work_group_size;
        int num_blocks = (no_of_nodes + num_threads - 1) / num_threads;

#ifdef PROFILING
        timer kernel_timer;
        double prof_kernel_time = 0.0;
        kernel_timer.reset();
        kernel_timer.start();
#endif

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

        do {
            h_over = false;
            checkCuda(cudaMemcpy(d_over, &h_over, sizeof(char), cudaMemcpyHostToDevice), "cudaMemcpy H2D d_over");

            launch_BFS_1(d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask,
                         d_graph_visited, d_cost, no_of_nodes, num_blocks, num_threads);
            checkCuda(cudaGetLastError(), "launch BFS_1");

            launch_BFS_2(d_graph_mask, d_updating_graph_mask, d_graph_visited,
                         d_over, no_of_nodes, num_blocks, num_threads);
            checkCuda(cudaGetLastError(), "launch BFS_2");

            checkCuda(cudaMemcpy(&h_over, d_over, sizeof(char), cudaMemcpyDeviceToHost), "cudaMemcpy D2H d_over");
        } while (h_over);

        checkCuda(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef PROFILING
        kernel_timer.stop();
        prof_kernel_time = kernel_timer.getTimeInSeconds();
#endif

#ifdef TIMING
        gettimeofday(&tv_d2h_start, NULL);
#endif

        checkCuda(cudaMemcpy(h_cost, d_cost, no_of_nodes * sizeof(int), cudaMemcpyDeviceToHost), "cudaMemcpy D2H d_cost");

#ifdef TIMING
        gettimeofday(&tv_d2h_end, NULL);
        tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
        d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

        gettimeofday(&tv_close_start, NULL);
#endif

#ifdef PROFILING
        std::cout << "kernel time(s):" << prof_kernel_time << std::endl;
#endif

        if (d_graph_nodes) cudaFree(d_graph_nodes);
        if (d_graph_edges) cudaFree(d_graph_edges);
        if (d_graph_mask) cudaFree(d_graph_mask);
        if (d_updating_graph_mask) cudaFree(d_updating_graph_mask);
        if (d_graph_visited) cudaFree(d_graph_visited);
        if (d_cost) cudaFree(d_cost);
        if (d_over) cudaFree(d_over);
    } catch (std::string msg) {
        if (d_graph_nodes) cudaFree(d_graph_nodes);
        if (d_graph_edges) cudaFree(d_graph_edges);
        if (d_graph_mask) cudaFree(d_graph_mask);
        if (d_updating_graph_mask) cudaFree(d_updating_graph_mask);
        if (d_graph_visited) cudaFree(d_graph_visited);
        if (d_cost) cudaFree(d_cost);
        if (d_over) cudaFree(d_over);
        std::string e_str = "in run_transpose_gpu -> ";
        e_str += msg;
        throw e_str;
    }

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

void Usage(int argc, char** argv) {
    (void)argc;
    fprintf(stderr, "Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[]) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    FILE *fp = NULL;
    Node* h_graph_nodes = NULL;
    char *h_graph_mask = NULL, *h_updating_graph_mask = NULL, *h_graph_visited = NULL;
    int *h_graph_edges = NULL;
    int *h_cost = NULL;
    int *h_cost_ref = NULL;

    try {
        char *input_f;
        if (argc < 2) {
            Usage(argc, argv);
            exit(0);
        }

        _clCmdParams(argc, argv);
        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f, "r");
        if (!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp, "%d", &no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if (no_of_nodes > MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)((no_of_nodes + MAX_THREADS_PER_BLOCK - 1) / MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        (void)num_of_blocks;
        work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node*)malloc(sizeof(Node) * no_of_nodes);
        h_graph_mask = (char*)malloc(sizeof(char) * no_of_nodes);
        h_updating_graph_mask = (char*)malloc(sizeof(char) * no_of_nodes);
        h_graph_visited = (char*)malloc(sizeof(char) * no_of_nodes);

        int start, edgeno;

        for (int i = 0; i < no_of_nodes; i++) {
            fscanf(fp, "%d %d", &start, &edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        fscanf(fp, "%d", &source);
        source = 0;

        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        fscanf(fp, "%d", &edge_list_size);
        int id, cost;
        h_graph_edges = (int*)malloc(sizeof(int) * edge_list_size);
        for (int i = 0; i < edge_list_size; i++) {
            fscanf(fp, "%d", &id);
            fscanf(fp, "%d", &cost);
            h_graph_edges[i] = id;
        }

        if (fp) {
            fclose(fp);
            fp = NULL;
        }

        h_cost = (int*)malloc(sizeof(int) * no_of_nodes);
        h_cost_ref = (int*)malloc(sizeof(int) * no_of_nodes);
        for (int i = 0; i < no_of_nodes; i++) {
            h_cost[i] = -1;
            h_cost_ref[i] = -1;
        }
        h_cost[source] = 0;
        h_cost_ref[source] = 0;

        run_bfs_gpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for (int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i] = false;
            h_updating_graph_mask[i] = false;
            h_graph_visited[i] = false;
        }

        source = 0;
        h_graph_mask[source] = true;
        h_graph_visited[source] = true;
        run_bfs_cpu(no_of_nodes, h_graph_nodes, edge_list_size, h_graph_edges,
                    h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    } catch (std::string msg) {
        std::cout << "--cambine: exception in main ->" << msg << std::endl;

        if (fp) fclose(fp);
        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);
    }

    return 0;
}

