static char device_type[3] = "";
static int device_id = 0;
static int platform_id = 0;

static __constant__ float c_ff_variable[NVAR];
static __constant__ float3 c_ff_flux_contribution_momentum_x[1];
static __constant__ float3 c_ff_flux_contribution_momentum_y[1];
static __constant__ float3 c_ff_flux_contribution_momentum_z[1];
static __constant__ float3 c_ff_flux_contribution_density_energy[1];

