	if (err != cudaSuccess) {
		throw msg;
	}
}

template <typename T>
T* alloc(int N){
	T* mem_d = nullptr;
	cuda_throw_if_error(cudaMalloc((void**)&mem_d, sizeof(T)*N), "cudaMalloc failed");
	return mem_d;
}

template <typename T>
void dealloc(T* array){
	if(array) cudaFree((void*)array);
}

template <typename T>
void copy(T* dst, T* src, int N){
	cuda_throw_if_error(cudaMemcpy(dst, src, N*sizeof(T), cudaMemcpyDeviceToDevice), "cudaMemcpy D2D failed");
}

template <typename T>
void upload(T* dst, T* src, int N){
	cuda_throw_if_error(cudaMemcpy(dst, src, N*sizeof(T), cudaMemcpyHostToDevice), "cudaMemcpy H2D failed");
}

template <typename T>
void download(T* dst, T* src, int N){
	cuda_throw_if_error(cudaMemcpy(dst, src, N*sizeof(T), cudaMemcpyDeviceToHost), "cudaMemcpy D2H failed");
}

void dump(float* variables, int nel, int nelr){
	float* h_variables = new float[nelr*NVAR];
	download(h_variables, variables, nelr*NVAR);

	{
		std::ofstream file("density.txt");
