__device__ inline int divRndUp_dev(int n, int d)
{
    return (n / d) + ((n % d) ? 1 : 0);
}

__device__ inline void mirror_dev(int *d, const int sizeD)
{
    if ((*d) >= sizeD) {
        (*d) = 2 * sizeD - 2 - (*d);
    } else if ((*d) < 0) {
        (*d) = -(*d);
    }
}

struct VerticalDWTPixelIO
{
    bool CHECKED;
    int end, stride;
};

__device__ inline int initialize_PixelIO(struct VerticalDWTPixelIO *pIO,
                                         bool CHECK,
                                         const int sizeX,
                                         const int sizeY,
                                         int firstX,
                                         int firstY)
{
    pIO->CHECKED = CHECK;
    pIO->end = pIO->CHECKED ? (sizeY * sizeX + firstX) : 0;
    pIO->stride = sizeX;
    return firstX + sizeX * firstY;
}

struct VerticalDWTPixelLoader
{
    bool CHECKED;
    int last;
};

__device__ inline void init_PixelLoader(struct VerticalDWTPixelLoader *loader,
                                        const int sizeX,
                                        const int sizeY,
                                        int firstX,
                                        const int firstY,
                                        struct VerticalDWTPixelIO *pIO,
                                        bool CHECK)
{
    mirror_dev(&firstX, sizeX);
    loader->last = initialize_PixelIO(pIO, CHECK, sizeX, sizeY, firstX, firstY) - sizeX;
}

__device__ inline void clear_PixelLoader(struct VerticalDWTPixelLoader *pLoader,
                                         struct VerticalDWTPixelIO *pIO)
{
    pLoader->last = 0;
    pIO->end = 0;
    pIO->stride = 0;
}

__device__ inline int loadFrom(struct VerticalDWTPixelLoader *pLoader,
                               const int *input,
                               struct VerticalDWTPixelIO *pIO,
                               int CHECK)
{
    pLoader->last += pIO->stride;
    if (CHECK && (pLoader->last == pIO->end)) {
        pLoader->last -= 2 * pIO->stride;
        pIO->stride = 0 - pIO->stride;
    }
    return input[pLoader->last];
}

struct VerticalDWTBandIO
{
    bool CHECKED;
    int end;
    int strideHighToLow;
    int strideLowToHigh;
};

__device__ inline int initialize_BandIO(struct VerticalDWTBandIO *bandIO,
                                        const int imageSizeX,
                                        const int imageSizeY,
                                        int firstX,
                                        int firstY)
{
    int columnOffset = firstX / 2;
    int verticalStride;

    if (firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUp_dev(imageSizeX, 2) * divRndUp_dev(imageSizeY, 2);
        bandIO->strideLowToHigh = (imageSizeX * imageSizeY) / 2;
    } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        bandIO->strideLowToHigh = divRndUp_dev(imageSizeY, 2) * imageSizeX;
    }

    bandIO->strideHighToLow = verticalStride - bandIO->strideLowToHigh;

    if (bandIO->CHECKED) {
        bandIO->end = columnOffset + (imageSizeY / 2) * verticalStride
                    + (imageSizeY & 1) * bandIO->strideLowToHigh;
    } else {
        bandIO->end = 0;
    }

    return columnOffset + (firstY / 2) * verticalStride
         + (firstY & 1) * bandIO->strideLowToHigh;
}

