__device__ inline int saveAndUpdate(struct VerticalDWTBandWriter *writer,
                                    bool CHECK,
                                    struct VerticalDWTBandIO *bandIO,
                                    int *output,
                                    int *item,
                                    int *stride)
{
    writer->CHECKED = CHECK;
    if ((!writer->CHECKED) || (writer->next != bandIO->end)) {
        output[writer->next] = *item;
        writer->next += *stride;
    }
    return writer->next;
}

__device__ inline void clear_BandWriter(struct VerticalDWTBandWriter *writer,
                                        struct VerticalDWTBandIO *bandIO)
{
    bandIO->end = 0;
    bandIO->strideHighToLow = 0;
    bandIO->strideLowToHigh = 0;
