    size = samplesNum * sizeof(T);
    std::vector<T> gpu_output(samplesNum);
    unsigned char *result = (unsigned char *)malloc(samplesNum);

    cudaMemcpy(gpu_output.data(), component_cuda, size, cudaMemcpyDeviceToHost);

    samplesToChar(result, gpu_output.data(), samplesNum);

    std::string outfile = std::string(filename) + suffix;
