static inline int divRndUp_host(int n, int d)
{
    return (n / d) + ((n % d) ? 1 : 0);
}

__device__ inline int divRndUp_dev(int n, int d)
{
    return (n / d) + ((n % d) ? 1 : 0);
}

__device__ inline void storeComponents_dev(int *d_r,
                                           int *d_g,
