template <typename T>
__global__ void c_CopySrcToComponentsKernel(T *d_r,
                                            T *d_g,
                                            T *d_b,
                                            const unsigned char *cl_d_src,
                                            int pixels)
{
    int x = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    __shared__ unsigned char sData[THREADS * 3];

    int globalOutputPosition = gX + x;
    int srcOffset = globalOutputPosition * 3;

    if (globalOutputPosition < pixels) {
        sData[3 * x + 0] = cl_d_src[srcOffset + 0];
        sData[3 * x + 1] = cl_d_src[srcOffset + 1];
        sData[3 * x + 2] = cl_d_src[srcOffset + 2];
    } else {
        sData[3 * x + 0] = 0;
        sData[3 * x + 1] = 0;
        sData[3 * x + 2] = 0;
    }

    __syncthreads();

    int offset = x * 3;
    int r = (int)(sData[offset + 0]);
    int g = (int)(sData[offset + 1]);
    int b = (int)(sData[offset + 2]);

    if (globalOutputPosition < pixels) {
        storeComponents_dev(d_r, d_g, d_b, r, g, b, globalOutputPosition);
    }
}

template <typename T>
__global__ void c_CopySrcToComponentKernel(T *d_c,
                                           const unsigned char *cl_d_src,
                                           int pixels)
{
    int x = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    __shared__ unsigned char sData[THREADS];

    int globalOutputPosition = gX + x;
    if (globalOutputPosition < pixels) {
        sData[x] = cl_d_src[globalOutputPosition];
    } else {
        sData[x] = 0;
    }

