    cudaMalloc((void **)&cl_backup, componentSize);
    cudaMemset(cl_c_r_out, 0, componentSize);
    cudaMemset(cl_backup, 0, componentSize);

    if (d->components == 3) {
        T *cl_c_g_out = 0;
        T *cl_c_b_out = 0;
        T *cl_c_r = 0;
        T *cl_c_g = 0;
        T *cl_c_b = 0;

        cudaMalloc((void **)&cl_c_g_out, componentSize);
        cudaMalloc((void **)&cl_c_b_out, componentSize);
        cudaMalloc((void **)&cl_c_r, componentSize);
        cudaMalloc((void **)&cl_c_g, componentSize);
        cudaMalloc((void **)&cl_c_b, componentSize);

        cudaMemset(cl_c_g_out, 0, componentSize);
        cudaMemset(cl_c_b_out, 0, componentSize);
        cudaMemset(cl_c_r, 0, componentSize);
        cudaMemset(cl_c_g, 0, componentSize);
