int main(int argc, char **argv)
{
    int optindex = 0;
    char ch;
    struct option longopts[] =
    {
        {"dimension",    required_argument, 0, 'D'},
        {"components",   required_argument, 0, 'c'},
        {"depth",        required_argument, 0, 'b'},
        {"level",        required_argument, 0, 'l'},
        {"device",       required_argument, 0, 'd'},
        {"platform",     required_argument, 0, 'p'},
        {"input-dir",    required_argument, 0, 'i'},
        {"forward",      no_argument,       0, 'f'},
        {"reverse",      no_argument,       0, 'r'},
        {"97",           no_argument,       0, '9'},
        {"53",           no_argument,       0, '5'},
        {"write-visual", no_argument,       0, 'w'},
        {"help",         no_argument,       0, 'h'}
    };

    int pixWidth = 0;
    int pixHeight = 0;
    int compCount = 3;
    int bitDepth = 8;
    int dwtLvls = 3;
    int forward = 1;
    int dwt97 = 0;
    int writeVisual = 0;
