template <typename T>
__global__ void k_CopySrcToComponents(T *d_r, T *d_g, T *d_b,
                                      const unsigned char *d_src,
                                      int pixels)
{
    int x = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    __shared__ unsigned char sData[THREADS * 3];

    int globalPixel = gX + x;
    int base = 3 * x;
    if (globalPixel < pixels) {
        int srcBase = 3 * globalPixel;
        sData[base + 0] = d_src[srcBase + 0];
        sData[base + 1] = d_src[srcBase + 1];
        sData[base + 2] = d_src[srcBase + 2];
    } else {
        sData[base + 0] = 0;
        sData[base + 1] = 0;
        sData[base + 2] = 0;
    }

    __syncthreads();

    if (globalPixel < pixels) {
        d_r[globalPixel] = convertSample<T>(sData[base + 0]);
        d_g[globalPixel] = convertSample<T>(sData[base + 1]);
        d_b[globalPixel] = convertSample<T>(sData[base + 2]);
    }
}

template <typename T>
__global__ void k_CopySrcToComponent(T *d_c,
                                     const unsigned char *d_src,
                                     int pixels)
{
    int x = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    __shared__ unsigned char sData[THREADS];

    int globalPixel = gX + x;
    sData[x] = (globalPixel < pixels) ? d_src[globalPixel] : 0;

    __syncthreads();

    if (globalPixel < pixels) {
        d_c[globalPixel] = convertSample<T>(sData[x]);
    }
}

template<typename T>
void rgbToComponents(T *d_r, T *d_g, T *d_b, unsigned char *src, int width, int height)
{
    int pixels = width * height;
    if (pixels <= 0) return;

    unsigned char *d_src = 0;
    cudaMalloc((void**)&d_src, pixels * 3 * sizeof(unsigned char));
    cudaMemcpy(d_src, src, pixels * 3 * sizeof(unsigned char), cudaMemcpyHostToDevice);

    int alignedPixels = DIVANDRND(pixels, THREADS) * THREADS;
    int blocks = alignedPixels / THREADS;

    k_CopySrcToComponents<T><<<blocks, THREADS>>>(d_r, d_g, d_b, d_src, pixels);
    cudaCheckError("k_CopySrcToComponents");

    cudaFree(d_src);
}

template<typename T>
void bwToComponent(T *d_c, unsigned char *src, int width, int height)
{
    int pixels = width * height;
    if (pixels <= 0) return;

    unsigned char *d_src = 0;
    cudaMalloc((void**)&d_src, pixels * sizeof(unsigned char));
    cudaMemcpy(d_src, src, pixels * sizeof(unsigned char), cudaMemcpyHostToDevice);

    int alignedPixels = DIVANDRND(pixels, THREADS) * THREADS;
    int blocks = alignedPixels / THREADS;

    k_CopySrcToComponent<T><<<blocks, THREADS>>>(d_c, d_src, pixels);
    cudaCheckError("k_CopySrcToComponent");

    cudaFree(d_src);
}

