#include <cstdio>
#include <cuda_runtime.h>
#include "common.h"
#include "dwt_cuda.h"

#define THREADS 256
#define BOUNDARY_X 2

namespace dwt_cuda {

__device__ __host__ static inline int divRndUp_i(int n, int d)
{
    return (n / d) + ((n % d) ? 1 : 0);
}

__device__ static inline void mirror_i(int *d, const int sizeD)
{
    if ((*d) >= sizeD) {
        (*d) = 2 * sizeD - 2 - (*d);
    } else if ((*d) < 0) {
        (*d) = -(*d);
    }
}

struct VerticalDWTPixelIO
{
    bool CHECKED;
    int end, stride;
};

__device__ static int initialize_PixelIO(VerticalDWTPixelIO *pIO,
                                         bool CHECK,
                                         const int sizeX,
                                         const int sizeY,
                                         int firstX,
                                         int firstY)
{
    pIO->CHECKED = CHECK;
    pIO->end = pIO->CHECKED ? (sizeY * sizeX + firstX) : 0;
    pIO->stride = sizeX;
    return firstX + sizeX * firstY;
}

struct VerticalDWTPixelLoader
{
    bool CHECKED;
    int last;
};

__device__ static void init_PixelLoader(VerticalDWTPixelLoader *loader,
                                        const int sizeX,
                                        const int sizeY,
                                        int firstX,
                                        const int firstY,
                                        VerticalDWTPixelIO *pIO,
                                        bool CHECK)
{
    mirror_i(&firstX, sizeX);
    loader->last = initialize_PixelIO(pIO, CHECK, sizeX, sizeY, firstX, firstY) - sizeX;
}

__device__ static void clear_PixelLoader(VerticalDWTPixelLoader *pLoader,
                                         VerticalDWTPixelIO *pIO)
{
    pLoader->last = 0;
    pIO->end = 0;
    pIO->stride = 0;
}

__device__ static int loadFrom(VerticalDWTPixelLoader *pLoader,
                               const int *input,
                               VerticalDWTPixelIO *pIO,
                               int CHECK)
{
    pLoader->last += pIO->stride;
    if(CHECK && (pLoader->last == pIO->end))
    {
        pLoader->last -= 2 * pIO->stride;
        pIO->stride = 0 - pIO->stride;
    }
    return input[pLoader->last];
}

struct VerticalDWTBandIO
{
    bool CHECKED;
    int end;
    int strideHighToLow;
    int strideLowToHigh;
};

__device__ static int initialize_BandIO(VerticalDWTBandIO *bandIO,
                                        const int imageSizeX,
                                        const int imageSizeY,
                                        int firstX,
                                        int firstY)
{
    int columnOffset = firstX / 2;
    int verticalStride;

    if(firstX & 1)
    {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUp_i(imageSizeX, 2) * divRndUp_i(imageSizeY, 2);
        bandIO->strideLowToHigh = (imageSizeX * imageSizeY) / 2;
    }
    else
    {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        bandIO->strideLowToHigh = divRndUp_i(imageSizeY, 2) * imageSizeX;
    }

    bandIO->strideHighToLow = verticalStride - bandIO->strideLowToHigh;

    if (bandIO->CHECKED)
    {
        bandIO->end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * bandIO->strideLowToHigh;
    }
    else
    {
        bandIO->end = 0;
    }

    return columnOffset + (firstY / 2) * verticalStride
          + (firstY & 1) * bandIO->strideLowToHigh;
}

struct VerticalDWTBandLoader
{
    bool CHECKED;
    int last;
};

struct VerticalDWTBandWriter
{
    bool CHECKED;
    int next;
};

__device__ static int saveAndUpdate(VerticalDWTBandWriter *writer,
                                    bool CHECK,
                                    VerticalDWTBandIO *bandIO,
                                    int *output,
                                    int *item,
                                    int *stride)
{
    writer->CHECKED = CHECK;
    if((!writer->CHECKED) || (writer->next != bandIO->end))
    {
        output[writer->next] = *item;
        writer->next += *stride;
    }
    return writer->next;
}

__device__ static void clear_BandWriter(VerticalDWTBandWriter *writer,
                                        VerticalDWTBandIO *bandIO)
{
    bandIO->end = 0;
    bandIO->strideHighToLow = 0;
    bandIO->strideLowToHigh = 0;
    writer->next = 0;
}

__device__ static void init_BandWriter(VerticalDWTBandWriter *writer,
                                       VerticalDWTBandIO *bandIO,
                                       const int imageSizeX,
                                       const int imageSizeY,
                                       const int firstX,
                                       const int firstY)
{
    if (firstX < imageSizeX)
    {
        writer->next = initialize_BandIO(bandIO, imageSizeX, imageSizeY, firstX, firstY);
    }
    else
    {
        clear_BandWriter(writer, bandIO);
    }
}

__device__ static int writeLowInto(VerticalDWTBandWriter *writer,
                                   VerticalDWTBandIO *bandIO,
                                   int *output,
                                   int *primary)
{
    return saveAndUpdate(writer, writer->CHECKED, bandIO, output, primary, &(bandIO->strideLowToHigh));
}

__device__ static int writeHighInto(VerticalDWTBandWriter *writer,
                                    VerticalDWTBandIO *bandIO,
                                    int *output,
                                    int *other)
{
    return saveAndUpdate(writer, writer->CHECKED, bandIO, output, other, &(bandIO->strideHighToLow));
}

struct TransformBuffer
{
    int SIZE_X, SIZE_Y;
    int VERTICAL_STRIDE;
    int SHM_BANKS, BUFFER_SIZE, PADDING, ODD_OFFSET;
    int data[2182];
};

__device__ static void horizontalStep(TransformBuffer *buffer,
                                      const int count,
                                      const int prevOffset,
                                      const int midOffset,
                                      const int nextOffset,
                                      int flag)
{
    const int STEPS = count / buffer->SIZE_X;
    const int finalCount = count % buffer->SIZE_X;
    const int finalOffset = count - finalCount;

    for(int i = 0; i < STEPS; i++)
    {
        const int previous = buffer->data[prevOffset + i * buffer->SIZE_X + threadIdx.x];
        const int next     = buffer->data[nextOffset + i * buffer->SIZE_X + threadIdx.x];
        int *center = &(buffer->data[midOffset + i * buffer->SIZE_X + threadIdx.x]);
        if (flag == 0)
        {
            *center -= (previous + next) / 2;
        } else if (flag == 1)
        {
            *center += (previous + next + 2) / 4;
        }
    }

    if(threadIdx.x < finalCount) {
        const int previous = buffer->data[prevOffset + finalOffset + threadIdx.x];
        const int next     = buffer->data[nextOffset + finalOffset + threadIdx.x];
        int *center = &(buffer->data[midOffset + finalOffset + threadIdx.x]);

        if (flag == 0)
        {
            *center -= (previous + next) / 2;
        } else if (flag == 1)
        {
            *center += (previous + next + 2) / 4;
        }
    }
}

__device__ static void forEachHorizontalOdd(TransformBuffer *buffer,
                                            const int firstLine,
                                            const int numLines,
                                            int flag)
{
    const int count = numLines * buffer->VERTICAL_STRIDE - 1;
    const int prevOffset = firstLine * buffer->VERTICAL_STRIDE;
    const int centerOffset = prevOffset + buffer->ODD_OFFSET;
    const int nextOffset = prevOffset + 1;

    horizontalStep(buffer, count, prevOffset, centerOffset, nextOffset, flag);
}

__device__ static void forEachHorizontalEven(TransformBuffer *buffer,
                                             const int firstLine,
                                             const int numLines,
                                             int flag)
{
    const int count = numLines * buffer->VERTICAL_STRIDE - 1;
    const int centerOffset = firstLine * buffer->VERTICAL_STRIDE + 1;
    const int prevOffset = firstLine * buffer->VERTICAL_STRIDE + buffer->ODD_OFFSET;
    const int nextOffset = prevOffset + 1;

    horizontalStep(buffer, count, prevOffset, centerOffset, nextOffset, flag);
}

__device__ static void forEachVerticalOdd(TransformBuffer *buffer,
                                          const int columnOffset,
                                          int flag)
{
    int steps = (buffer->SIZE_Y - 1) / 2;
    for (int i = 0; i < steps; i++)
    {
        int row = i * 2 + 1;
        int prev = buffer->data[columnOffset + (row - 1) * buffer->VERTICAL_STRIDE];
        int next = buffer->data[columnOffset + (row + 1) * buffer->VERTICAL_STRIDE];

        if (flag == 0)
        {
            buffer->data[columnOffset + row * buffer->VERTICAL_STRIDE] -= (prev + next) / 2;
        }
    }
}

__device__ static void forEachVerticalEven(TransformBuffer *buffer,
                                           const int columnOffset,
                                           int flag)
{
    if(buffer->SIZE_Y > 3)
    {
        int steps = (int)(buffer->SIZE_Y / 2) - 1;

        for(int i = 0; i < steps; i++)
        {
            int row = 2 + i * 2;
            int prev = buffer->data[columnOffset + (row - 1) * buffer->VERTICAL_STRIDE];
            int next = buffer->data[columnOffset + (row + 1) * buffer->VERTICAL_STRIDE];

            if (flag == 1)
            {
                buffer->data[columnOffset + row * buffer->VERTICAL_STRIDE] += (prev + next + 2) / 4;
            }
        }
    }
}

struct FDWT53Column
{
    bool CHECKED_LOADER;
    VerticalDWTPixelLoader loader;
    int offset;
    int pixel0, pixel1, pixel2;
};

__device__ static void clear_FDWT53Column(FDWT53Column *st_FDWT53Column,
                                          VerticalDWTPixelIO *pIO)
{
    st_FDWT53Column->offset = 0;
    st_FDWT53Column->pixel0 = 0;
    st_FDWT53Column->pixel1 = 0;
    st_FDWT53Column->pixel2 = 0;
    clear_PixelLoader(&(st_FDWT53Column->loader), pIO);
}

struct FDWT53 {
    int WIN_SIZE_X, WIN_SIZE_Y;
    FDWT53Column column;
    TransformBuffer buffer;
    int STRIDE;
};

__device__ static int getColumnOffset(int columnIndex,
                                      TransformBuffer * buffer)
{
    columnIndex += BOUNDARY_X;
    return columnIndex / 2 + (columnIndex & 1) * buffer->ODD_OFFSET;
}

__device__ static void initColumn(FDWT53 * fdwt53,
                                  FDWT53Column *column,
                                  bool CHECKED,
                                  const int *input,
                                  const int sizeX,
                                  const int sizeY,
                                  const int colIndex,
                                  const int firstY,
                                  VerticalDWTPixelIO *pIO)
{
    column->CHECKED_LOADER = CHECKED;
    column->offset = getColumnOffset(colIndex, &fdwt53->buffer);

    const int firstX = blockIdx.x * fdwt53->WIN_SIZE_X + colIndex;
    if(blockIdx.y == 0)
    {
        init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY, pIO, CHECKED);
        column->pixel2 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel1 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel0 = loadFrom(&(column->loader), input, pIO, CHECKED);
        init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY + 1, pIO, CHECKED);
    }
    else
    {
        init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY - 2, pIO, CHECKED);
        column->pixel0 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel1 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel2 = loadFrom(&(column->loader), input, pIO, CHECKED);
    }
}

__device__ static void loadAndVerticallyTransform(FDWT53 *fdwt53,
                                                  FDWT53Column *column,
                                                  bool CHECKED,
                                                  const int *input,
                                                  VerticalDWTPixelIO *pIO)
{
    fdwt53->buffer.data[column->offset + 0 * fdwt53->STRIDE] = column->pixel0;
    fdwt53->buffer.data[column->offset + 1 * fdwt53->STRIDE] = column->pixel1;
    fdwt53->buffer.data[column->offset + 2 * fdwt53->STRIDE] = column->pixel2;

    for (int i = 3; i < (3 + fdwt53->WIN_SIZE_Y); i++)
    {
        fdwt53->buffer.data[column->offset + i * fdwt53->STRIDE] =
            loadFrom(&(column->loader), input, pIO, CHECKED);
    }

    column->pixel0 = fdwt53->buffer.data[column->offset + (fdwt53->WIN_SIZE_Y + 0) * fdwt53->STRIDE];
    column->pixel1 = fdwt53->buffer.data[column->offset + (fdwt53->WIN_SIZE_Y + 1) * fdwt53->STRIDE];
    column->pixel2 = fdwt53->buffer.data[column->offset + (fdwt53->WIN_SIZE_Y + 2) * fdwt53->STRIDE];

    int flag = 0;
    forEachVerticalOdd(&fdwt53->buffer, column->offset, flag);
    flag = 1;
    forEachVerticalEven(&fdwt53->buffer, column->offset, flag);
}

__device__ static void transform(FDWT53 *fdwt53,
                                 bool CHECK_LOADS,
                                 bool CHECK_WRITES,
                                 const int *in,
                                 int *out,
                                 const int sizeX,
                                 const int sizeY,
                                 const int winSteps)
{
    FDWT53Column column; column.CHECKED_LOADER = CHECK_LOADS;
    VerticalDWTPixelIO pIO;
    FDWT53Column boundaryColumn; boundaryColumn.CHECKED_LOADER = CHECK_LOADS;
    VerticalDWTPixelIO pIO_b;

    const int firstY = blockIdx.y * fdwt53->WIN_SIZE_Y * winSteps;
    initColumn(fdwt53, &column, CHECK_LOADS, in, sizeX, sizeY, threadIdx.x, firstY, &pIO);

    clear_FDWT53Column(&boundaryColumn, &pIO_b);
    if (threadIdx.x < 3) {
        const int colId = threadIdx.x + ((threadIdx.x == 0) ? fdwt53->WIN_SIZE_X : -3);
        initColumn(fdwt53, &boundaryColumn, CHECK_LOADS, in, sizeX, sizeY, colId, firstY, &pIO_b);
    }

    const int outColumnIndex =
        (threadIdx.x * 2) -
        (fdwt53->WIN_SIZE_X - 1) * (threadIdx.x / (fdwt53->WIN_SIZE_X / 2));

    const int outColumnOffset = getColumnOffset(outColumnIndex, &(fdwt53->buffer));

    const int outputFirstX = blockIdx.x * fdwt53->WIN_SIZE_X + outColumnIndex;
    VerticalDWTBandWriter writer; writer.CHECKED = CHECK_WRITES;
    VerticalDWTBandIO bandIO; bandIO.CHECKED = CHECK_WRITES;

    init_BandWriter(&writer, &bandIO, sizeX, sizeY, outputFirstX, firstY);

    for(int w = 0; w < winSteps; w++)
    {
        loadAndVerticallyTransform(fdwt53, &column, CHECK_LOADS, in, &pIO);
        if (threadIdx.x < 3)
        {
            loadAndVerticallyTransform(fdwt53, &boundaryColumn, CHECK_LOADS, in, &pIO_b);
        }

        __syncthreads();

        int flag = 0;
        forEachHorizontalOdd(&(fdwt53->buffer), 2, fdwt53->WIN_SIZE_Y, flag);
        __syncthreads();

        flag = 1;
        forEachHorizontalEven(&(fdwt53->buffer), 2, fdwt53->WIN_SIZE_Y, flag);
        __syncthreads();

        for(int r = 2; r < (2 + fdwt53->WIN_SIZE_Y); r += 2)
        {
            writeLowInto(&writer, &bandIO, out,
                         &(fdwt53->buffer.data[outColumnOffset + r * fdwt53->buffer.VERTICAL_STRIDE]));
            writeHighInto(&writer, &bandIO, out,
                          &(fdwt53->buffer.data[outColumnOffset + (r + 1) * fdwt53->buffer.VERTICAL_STRIDE]));
        }

        __syncthreads();
    }
}

__global__ static void cl_fdwt53Kernel(const int *in,
                                       int *out,
                                       const int sx,
                                       const int sy,
                                       const int steps,
                                       int WIN_SIZE_X,
                                       int WIN_SIZE_Y)
{
    __shared__ FDWT53 fdwt53;

    if (threadIdx.x == 0) {
        fdwt53.WIN_SIZE_X = WIN_SIZE_X;
        fdwt53.WIN_SIZE_Y = WIN_SIZE_Y;
        fdwt53.buffer.SIZE_X = fdwt53.WIN_SIZE_X;
        fdwt53.buffer.SIZE_Y = fdwt53.WIN_SIZE_Y + 3;
        fdwt53.buffer.VERTICAL_STRIDE = BOUNDARY_X + (fdwt53.buffer.SIZE_X / 2);
        fdwt53.buffer.SHM_BANKS = 32;
        fdwt53.buffer.BUFFER_SIZE = fdwt53.buffer.VERTICAL_STRIDE * fdwt53.buffer.SIZE_Y;
        fdwt53.buffer.PADDING =
            fdwt53.buffer.SHM_BANKS -
            ((fdwt53.buffer.BUFFER_SIZE + fdwt53.buffer.SHM_BANKS / 2) % fdwt53.buffer.SHM_BANKS);
        fdwt53.buffer.ODD_OFFSET = fdwt53.buffer.BUFFER_SIZE + fdwt53.buffer.PADDING;
        fdwt53.STRIDE = fdwt53.buffer.VERTICAL_STRIDE;
    }

    for(int i = threadIdx.x; i < (int)(sizeof(fdwt53.buffer.data) / sizeof(int)); i += blockDim.x) {
        fdwt53.buffer.data[i] = 0;
    }

    __syncthreads();

    const int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 1;
    const int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 1;
    const bool atRightBoudary = maxX >= sx;
    const bool atBottomBoudary = maxY >= sy;

    if(atBottomBoudary)
    {
        transform(&fdwt53, true, true, in, out, sx, sy, steps);
    }
    else if(atRightBoudary)
    {
        transform(&fdwt53, false, true, in, out, sx, sy, steps);
    }
    else
    {
        transform(&fdwt53, false, false, in, out, sx, sy, steps);
    }
}

static void launchFDWT53Kernel(int WIN_SX, int WIN_SY, int *in, int *out, int sx, int sy)
{
    const int steps = (sy / (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);

    int gx = (sx / WIN_SX) + ((sx % WIN_SX) ? 1 : 0);
    int gy = (sy / (WIN_SY * steps)) + ((sy % (WIN_SY * steps)) ? 1 : 0);

    printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);

    dim3 block(WIN_SX, 1, 1);
    dim3 grid(gx, gy, 1);

    cl_fdwt53Kernel<<<grid, block>>>(in, out, sx, sy, steps, WIN_SX, WIN_SY);
    cudaCheckError("cl_fdwt53Kernel");

    printf("kl_fdwt53Kernel in launchFDW53Kernel has finished\n");
}

static void memCopy(int *dest, const int *src, const size_t sx, const size_t sy)
{
    cudaMemcpy(dest, src, sx * sy * sizeof(int), cudaMemcpyDeviceToDevice);
}

void fdwt53(int * in, int * out, int sizeX, int sizeY, int levels)
{
    if(sizeX >= 960)
    {
        launchFDWT53Kernel(192, 8, in, out, sizeX, sizeY);
    }
    else if (sizeX >= 480)
    {
        launchFDWT53Kernel(128, 8, in, out, sizeX, sizeY);
    }
    else
    {
        launchFDWT53Kernel(64, 8, in, out, sizeX, sizeY);
    }

    if (levels > 1)
    {
        const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
        const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
        memCopy(in, out, llSizeX, llSizeY);

        fdwt53(in, out, llSizeX, llSizeY, levels - 1);
    }
}

