        return -1;
    }

    if (forward == 0)
    {
        writeVisual = 0;
    }

    int cudaDeviceCount = 0;
    cudaGetDeviceCount(&cudaDeviceCount);
    if (cudaDeviceCount <= 0) {
        std::cerr << "No CUDA devices available." << std::endl;
        return 1;
    }
    if (device < 0 || device >= cudaDeviceCount) device = 0;
    cudaSetDevice(device);

