        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif
    context = cl_init_context(platform, device, quiet);
#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    if (size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            perror("fopen");
            return 1;
        }

        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);

        a = (float *)malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++)
            b[i] = 1.0f;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    ForwardSub(context, a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cl_cleanup();

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}

void ForwardSub(cl_context context, float *a, float *b, float *m, int size, int timing) {
    (void)context;
    (void)timing;

    float *a_dev = NULL, *b_dev = NULL, *m_dev = NULL;
    float writeMB = 0, readMB = 0;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    cuda_errchk(cudaMalloc((void **)&a_dev, sizeof(float) * size * size), "allocating a_dev");
    cuda_errchk(cudaMalloc((void **)&b_dev, sizeof(float) * size), "allocating b_dev");
    cuda_errchk(cudaMalloc((void **)&m_dev, sizeof(float) * size * size), "allocating m_dev");
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    cudaEvent_t startEvent, stopEvent;
    cuda_errchk(cudaEventCreate(&startEvent), "creating start event");
    cuda_errchk(cudaEventCreate(&stopEvent), "creating stop event");

    cuda_errchk(cudaEventRecord(startEvent, 0), "record H2D start");
#endif
    cuda_errchk(cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice),
                "copying a to device");
#ifdef TIMING
    cuda_errchk(cudaEventRecord(stopEvent, 0), "record H2D stop");
    h2d_time += eventTime(startEvent, stopEvent);

    cuda_errchk(cudaEventRecord(startEvent, 0), "record H2D start");
#endif
    cuda_errchk(cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice),
                "copying b to device");
#ifdef TIMING
    cuda_errchk(cudaEventRecord(stopEvent, 0), "record H2D stop");
    h2d_time += eventTime(startEvent, stopEvent);

    cuda_errchk(cudaEventRecord(startEvent, 0), "record H2D start");
#endif
    cuda_errchk(cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice),
                "copying m to device");
#ifdef TIMING
    cuda_errchk(cudaEventRecord(stopEvent, 0), "record H2D stop");
    h2d_time += eventTime(startEvent, stopEvent);
#endif

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    int fan1Block = (BLOCK_SIZE_0 > 0) ? BLOCK_SIZE_0 : 256;
    int fan2BlockX = (BLOCK_SIZE_1_X > 0) ? BLOCK_SIZE_1_X : 16;
    int fan2BlockY = (BLOCK_SIZE_1_Y > 0) ? BLOCK_SIZE_1_Y : 16;

    dim3 block1((unsigned int)fan1Block);
    dim3 block2((unsigned int)fan2BlockX, (unsigned int)fan2BlockY);

    int t;
    for (t = 0; t < (size - 1); t++) {
        dim3 grid1((unsigned int)((size + block1.x - 1) / block1.x));
#ifdef TIMING
        cuda_errchk(cudaEventRecord(startEvent, 0), "record kernel start");
#endif
        Fan1<<<grid1, block1>>>(m_dev, a_dev, b_dev, size, t);
        cuda_errchk(cudaGetLastError(), "launching Fan1");
        cuda_errchk(cudaDeviceSynchronize(), "synchronizing Fan1");
#ifdef TIMING
        cuda_errchk(cudaEventRecord(stopEvent, 0), "record kernel stop");
        kernel_time += eventTime(startEvent, stopEvent);
#endif

        dim3 grid2((unsigned int)((size + block2.x - 1) / block2.x),
                   (unsigned int)((size + block2.y - 1) / block2.y));
#ifdef TIMING
        cuda_errchk(cudaEventRecord(startEvent, 0), "record kernel start");
#endif
        Fan2<<<grid2, block2>>>(m_dev, a_dev, b_dev, size, t);
        cuda_errchk(cudaGetLastError(), "launching Fan2");
        cuda_errchk(cudaDeviceSynchronize(), "synchronizing Fan2");
#ifdef TIMING
        cuda_errchk(cudaEventRecord(stopEvent, 0), "record kernel stop");
        kernel_time += eventTime(startEvent, stopEvent);
#endif
    }

#ifdef TIMING
    cuda_errchk(cudaEventRecord(startEvent, 0), "record D2H start");
#endif
    cuda_errchk(cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost),
                "copying a to host");
#ifdef TIMING
    cuda_errchk(cudaEventRecord(stopEvent, 0), "record D2H stop");
    d2h_time += eventTime(startEvent, stopEvent);

    cuda_errchk(cudaEventRecord(startEvent, 0), "record D2H start");
#endif
    cuda_errchk(cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost),
                "copying b to host");
#ifdef TIMING
    cuda_errchk(cudaEventRecord(stopEvent, 0), "record D2H stop");
    d2h_time += eventTime(startEvent, stopEvent);

    cuda_errchk(cudaEventRecord(startEvent, 0), "record D2H start");
#endif
    cuda_errchk(cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost),
                "copying m to host");
#ifdef TIMING
    cuda_errchk(cudaEventRecord(stopEvent, 0), "record D2H stop");
    d2h_time += eventTime(startEvent, stopEvent);
#endif

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);
    cuda_errchk(cudaDeviceSynchronize(), "final synchronize");

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t", size, size);
    printf("%f [%.2fMB]\t", h2d_time, writeMB);
    printf("%f\t", kernel_time);
    printf("%f [%.2fMB]\t", d2h_time, readMB);
    printf("%f\n\n", h2d_time + kernel_time + d2h_time);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cuda_errchk(cudaFree(a_dev), "freeing a_dev");
    cuda_errchk(cudaFree(b_dev), "freeing b_dev");
    cuda_errchk(cudaFree(m_dev), "freeing m_dev");
#ifdef TIMING
    cuda_errchk(cudaEventDestroy(startEvent), "destroying start event");
    cuda_errchk(cudaEventDestroy(stopEvent), "destroying stop event");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
}

int parseCommandline(int argc, char *argv[], char *filename,
