}

static float timedMemcpy(void *dst, const void *src, size_t size, cudaMemcpyKind kind) {
    cudaEvent_t start, stop;
    float ms = 0.0f;
    cuda_err(cudaEventCreate(&start), "creating event");
    cuda_err(cudaEventCreate(&stop), "creating event");
    cuda_err(cudaEventRecord(start, 0), "recording event");
    cuda_err(cudaMemcpy(dst, src, size, kind), "copying memory");
    cuda_err(cudaEventRecord(stop, 0), "recording event");
    cuda_err(cudaEventSynchronize(stop), "synchronizing event");
    cuda_err(cudaEventElapsedTime(&ms, start, stop), "elapsed time");
    cuda_err(cudaEventDestroy(start), "destroying event");
    cuda_err(cudaEventDestroy(stop), "destroying event");
