__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        *(m_dev + size * (globalId + t + 1) + t) =
            *(a_dev + size * (globalId + t + 1) + t) / *(a_dev + size * t + t);
    }
}

__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -=
            m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -=
                m_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] * b_dev[t];
        }
    }
}

void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01f;
    float *coe = (float *)malloc((2 * size - 1) * sizeof(float));
    float coe_i = 0.0f;

    if (coe == NULL) {
        perror("malloc");
        exit(-1);
    }

    for (i = 0; i < size; i++) {
        coe_i = 10.0f * expf(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }

    free(coe);
}

cl_context cl_init_context(int platform, int dev, int quiet) {
    int printInfo = 1;
    int numDevices = 0;
    cudaError_t cerr = cudaGetDeviceCount(&numDevices);

    if (printInfo) printf("Number of platforms detected:%d\n", 1);

    if (cerr != cudaSuccess || numDevices <= 0) {
        printf("No OpenCL platforms found\n");
        exit(0);
    }

    if (printInfo) printf("Checking For OpenCl Compatible Devices\n");
    if (printInfo) printf("Platform %d\n", 0);
    if (printInfo) printf("vendor: NVIDIA Corporation\n");
    if (printInfo) printf("no of devices: %u\n", (unsigned int)numDevices);

    for (int j = 0; j < numDevices; j++) {
        cudaDeviceProp prop;
        cuda_err(cudaGetDeviceProperties(&prop, j), "getting device properties");
        if (printInfo) printf("\tdevice %d: NVIDIA Corporation %s\n", j, prop.name);
    }

    int platform_touse = platform;
    unsigned int device_touse = (unsigned int)dev;
    if (!quiet) printf("\nUsing Platform %d Device %d \n", platform_touse, device_touse);

    if (platform_touse != 0 || device_touse >= (unsigned int)numDevices) {
        printf("Invalid Device Number\n");
        exit(1);
    }

    cudaDeviceProp prop;
    cuda_err(cudaGetDeviceProperties(&prop, device_touse), "getting device properties");
    cuda_err(cudaSetDevice(device_touse), "setting device");

    if (!quiet) printf("Creating GPU Context\n");
#ifdef TIMING
    if (!quiet) printf("Profiling enabled\n");
#endif

    return 0;
}

