void ForwardSub(cl_context context, float *a, float *b, float *m, int size, int timing) {
    (void)context;
    (void)timing;

    float *a_dev = NULL, *b_dev = NULL, *m_dev = NULL;
    float writeMB = 0.0f, readMB = 0.0f;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    cuda_err(cudaMalloc((void **)&a_dev, sizeof(float) * size * size), "allocating a_dev");
    cuda_err(cudaMalloc((void **)&b_dev, sizeof(float) * size), "allocating b_dev");
    cuda_err(cudaMalloc((void **)&m_dev, sizeof(float) * size * size), "allocating m_dev");
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    h2d_time += timedMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    h2d_time += timedMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice);
    h2d_time += timedMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice);
#else
    cuda_err(cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice), "copying a to device");
    cuda_err(cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice), "copying b to device");
    cuda_err(cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice), "copying m to device");
#endif

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    int fan1_threads = (BLOCK_SIZE_0 > 0) ? BLOCK_SIZE_0 : 256;
    int fan2_block_x = (BLOCK_SIZE_1_X > 0) ? BLOCK_SIZE_1_X : 16;
    int fan2_block_y = (BLOCK_SIZE_1_Y > 0) ? BLOCK_SIZE_1_Y : 16;

    if (fan2_block_x * fan2_block_y > 1024) {
        fan2_block_x = 16;
        fan2_block_y = 16;
    }

    int t;
    for (t = 0; t < (size - 1); t++) {
        int fan1_work = size - 1 - t;
        if (fan1_work > 0) {
            dim3 block1((unsigned int)fan1_threads, 1, 1);
            dim3 grid1((unsigned int)((fan1_work + fan1_threads - 1) / fan1_threads), 1, 1);

#ifdef TIMING
            cudaEvent_t kstart, kstop;
            float kms = 0.0f;
            cuda_err(cudaEventCreate(&kstart), "creating event");
            cuda_err(cudaEventCreate(&kstop), "creating event");
            cuda_err(cudaEventRecord(kstart, 0), "recording event");
            Fan1<<<grid1, block1>>>(m_dev, a_dev, b_dev, size, t);
            cuda_err(cudaGetLastError(), "launching Fan1");
            cuda_err(cudaEventRecord(kstop, 0), "recording event");
            cuda_err(cudaEventSynchronize(kstop), "synchronizing event");
            cuda_err(cudaEventElapsedTime(&kms, kstart, kstop), "elapsed time");
            kernel_time += kms;
            cuda_err(cudaEventDestroy(kstart), "destroying event");
            cuda_err(cudaEventDestroy(kstop), "destroying event");
#else
            Fan1<<<grid1, block1>>>(m_dev, a_dev, b_dev, size, t);
            cuda_err(cudaGetLastError(), "launching Fan1");
#endif
        }

        int fan2_work_x = size - 1 - t;
        int fan2_work_y = size - t;
        if (fan2_work_x > 0 && fan2_work_y > 0) {
            dim3 block2((unsigned int)fan2_block_x, (unsigned int)fan2_block_y, 1);
            dim3 grid2((unsigned int)((fan2_work_x + fan2_block_x - 1) / fan2_block_x),
                       (unsigned int)((fan2_work_y + fan2_block_y - 1) / fan2_block_y),
                       1);

#ifdef TIMING
            cudaEvent_t kstart2, kstop2;
            float kms2 = 0.0f;
            cuda_err(cudaEventCreate(&kstart2), "creating event");
            cuda_err(cudaEventCreate(&kstop2), "creating event");
            cuda_err(cudaEventRecord(kstart2, 0), "recording event");
            Fan2<<<grid2, block2>>>(m_dev, a_dev, b_dev, size, t);
            cuda_err(cudaGetLastError(), "launching Fan2");
            cuda_err(cudaEventRecord(kstop2, 0), "recording event");
            cuda_err(cudaEventSynchronize(kstop2), "synchronizing event");
            cuda_err(cudaEventElapsedTime(&kms2, kstart2, kstop2), "elapsed time");
            kernel_time += kms2;
            cuda_err(cudaEventDestroy(kstart2), "destroying event");
            cuda_err(cudaEventDestroy(kstop2), "destroying event");
#else
            Fan2<<<grid2, block2>>>(m_dev, a_dev, b_dev, size, t);
            cuda_err(cudaGetLastError(), "launching Fan2");
#endif
        }
    }

    cuda_err(cudaDeviceSynchronize(), "synchronizing device");

#ifdef TIMING
    d2h_time += timedMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    d2h_time += timedMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost);
    d2h_time += timedMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
#else
    cuda_err(cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "copying a to host");
    cuda_err(cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost), "copying b to host");
    cuda_err(cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "copying m to host");
#endif

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t", size, size);
    printf("%f [%.2fMB]\t", h2d_time, writeMB);
    printf("%f\t", kernel_time);
    printf("%f [%.2fMB]\t", d2h_time, readMB);
    printf("%f\n\n", h2d_time + kernel_time + d2h_time);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cuda_err(cudaFree(a_dev), "freeing a_dev");
    cuda_err(cudaFree(b_dev), "freeing b_dev");
    cuda_err(cudaFree(m_dev), "freeing m_dev");
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
}

int main(int argc, char *argv[]) {
    printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n",
           BLOCK_SIZE_0, BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);

    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;

    FILE *fp;

    char filename[200];
    filename[0] = '\0';
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    if (parseCommandline(argc, argv, filename,
                         &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif
    context = cl_init_context(platform, device, quiet);
#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    if (size < 1) {
        fp = fopen(filename, "r");
        if (fp == NULL) {
            perror("fopen");
            return 1;
        }
        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        if (a == NULL) {
            perror("malloc");
            fclose(fp);
            return 1;
        }
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        if (b == NULL) {
            perror("malloc");
            free(a);
            fclose(fp);
            return 1;
        }
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);

        a = (float *)malloc(size * size * sizeof(float));
        b = (float *)malloc(size * sizeof(float));
        if (a == NULL || b == NULL) {
            perror("malloc");
            free(a);
            free(b);
            return 1;
        }

        create_matrix(a, size);

        for (int i = 0; i < size; i++)
            b[i] = 1.0f;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));
    if (m == NULL || finalVec == NULL) {
        perror("malloc");
        free(m);
        free(a);
        free(b);
        free(finalVec);
        return 1;
    }

    InitPerRun(size, m);

    ForwardSub(context, a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cl_cleanup();

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}

