static inline void cuda_errchk(cudaError_t err, const char *msg) {
    if (err != cudaSuccess) {
        std::fprintf(stderr, "CUDA Error: %s %s\n", cudaGetErrorString(err), msg);
        std::exit(1);
    }
}

static inline void tvsub(const struct timeval *end, const struct timeval *start, struct timeval *result) {
    result->tv_sec = end->tv_sec - start->tv_sec;
    result->tv_usec = end->tv_usec - start->tv_usec;
    if (result->tv_usec < 0) {
        --result->tv_sec;
        result->tv_usec += 1000000;
    }
}

static inline float elapsed_ms_now(const struct timeval &start, const struct timeval &end) {
    struct timeval diff;
    tvsub(&end, &start, &diff);
    return diff.tv_sec * 1000.0f + (float)diff.tv_usec / 1000.0f;
}

#ifdef TIMING
static float cuda_event_elapsed_ms(cudaEvent_t start, cudaEvent_t stop) {
    float ms = 0.0f;
    cuda_errchk(cudaEventSynchronize(stop), "synchronizing event");
    cuda_errchk(cudaEventElapsedTime(&ms, start, stop), "elapsed time");
    return ms;
}
#endif

__global__ void Fan1(float *m_dev, float *a_dev, float *b_dev, const int size, const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;
    if (globalId < size - 1 - t) {
        m_dev[size * (globalId + t + 1) + t] =
            a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2(float *m_dev, float *a_dev, float *b_dev, const int size, const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -=
            m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -=
                m_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] * b_dev[t];
        }
    }
}

void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01f;
    float *coe = (float *)std::malloc((2 * size - 1) * sizeof(float));
    if (!coe) {
        std::perror("malloc");
        std::exit(-1);
    }

    float coe_i = 0.0f;
    for (i = 0; i < size; i++) {
        coe_i = 10.0f * std::exp(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }

    std::free(coe);
}

cl_context cl_init_context(int platform, int dev, int quiet) {
    int printInfo = 1;
    int numDevices = 0;

    cudaError_t cerr = cudaGetDeviceCount(&numDevices);
    if (cerr != cudaSuccess || numDevices <= 0) {
        std::printf("No OpenCL platforms found\n");
        std::exit(0);
    }

    if (printInfo) std::printf("Number of platforms detected:%d\n", 1);
    if (printInfo) std::printf("Checking For OpenCl Compatible Devices\n");
    if (printInfo) std::printf("Platform %d\n", 0);
    if (printInfo) std::printf("vendor: NVIDIA Corporation\n");

    if (numDevices == 0) {
        std::printf("There are no devices for Platform %d\n", 0);
        std::exit(0);
    } else {
        if (printInfo) std::printf("no of devices: %u\n", (unsigned int)numDevices);
    }

    for (int j = 0; j < numDevices; j++) {
        cudaDeviceProp prop;
        cuda_errchk(cudaGetDeviceProperties(&prop, j), "getting device properties");
        if (printInfo) std::printf("\tdevice %d: %s %s\n", j, "NVIDIA Corporation", prop.name);
    }

    int platform_touse = platform;
    unsigned int device_touse = (unsigned int)dev;

    if (platform_touse != 0) {
        std::printf("Invalid Device Number\n");
        std::exit(1);
    }

    if (!quiet) std::printf("\nUsing Platform %d Device %d \n", platform_touse, device_touse);

    if ((int)device_touse >= numDevices) {
        std::printf("Invalid Device Number\n");
        std::exit(1);
    }

    cudaDeviceProp prop;
    cuda_errchk(cudaGetDeviceProperties(&prop, device_touse), "getting device properties");
    cuda_errchk(cudaSetDevice(device_touse), "setting device");

    if (!quiet) std::printf("Creating GPU Context\n");

    return 0;
}

void cl_cleanup() {
    cudaDeviceReset();
}

