void ForwardSub(cl_context context, float *a, float *b, float *m, int size, int timing) {
    (void)context;
    (void)timing;

    float *a_dev = NULL, *b_dev = NULL, *m_dev = NULL;
    float writeMB = 0, readMB = 0;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    cuda_errchk(cudaMalloc((void **)&a_dev, sizeof(float) * size * size), "allocating a_dev");
    cuda_errchk(cudaMalloc((void **)&b_dev, sizeof(float) * size), "allocating b_dev");
    cuda_errchk(cudaMalloc((void **)&m_dev, sizeof(float) * size * size), "allocating m_dev");
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    {
        cudaEvent_t start, stop;
        cuda_errchk(cudaEventCreate(&start), "creating event");
        cuda_errchk(cudaEventCreate(&stop), "creating event");
        cuda_errchk(cudaEventRecord(start), "record event");
        cuda_errchk(cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice), "copying a to device");
        cuda_errchk(cudaEventRecord(stop), "record event");
        h2d_time += cuda_event_elapsed_ms(start, stop);
        cudaEventDestroy(start);
        cudaEventDestroy(stop);
    }
    {
        cudaEvent_t start, stop;
        cuda_errchk(cudaEventCreate(&start), "creating event");
        cuda_errchk(cudaEventCreate(&stop), "creating event");
        cuda_errchk(cudaEventRecord(start), "record event");
        cuda_errchk(cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice), "copying b to device");
        cuda_errchk(cudaEventRecord(stop), "record event");
        h2d_time += cuda_event_elapsed_ms(start, stop);
        cudaEventDestroy(start);
        cudaEventDestroy(stop);
    }
    {
        cudaEvent_t start, stop;
        cuda_errchk(cudaEventCreate(&start), "creating event");
