    std::printf("\n");
    std::printf("filename     the filename that holds the matrix data\n");
    std::printf("\n");
    std::printf("-h           Display the help file\n");
    std::printf("-q           Quiet mode. Suppress all text output.\n");
    std::printf("-t           Print timing information.\n");
    std::printf("\n");
    std::printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    std::printf("-d [int]     Choose the device (must choose both platform and device)\n");
    std::printf("\n");
    std::printf("\n");
    std::printf("Notes: 1. The filename is required as the first parameter.\n");
    std::printf("       2. If you declare either the device or the platform,\n");
