	read_data(input_file_name,
				common.endoPoints,
				endoRow,
				endoCol,
				common.epiPoints,
				epiRow,
				epiCol);

	kernel_gpu_opencl_wrapper(common,
								endoRow,
								endoCol,
								tEndoRowLoc,
								tEndoColLoc,
								epiRow,
								epiCol,
								tEpiRowLoc,
								tEpiColLoc,
								frames);

#ifdef OUTPUT
	write_data("result.txt",
			common.no_frames,
