static void tvsub(const struct timeval *end, const struct timeval *start, struct timeval *diff) {
    diff->tv_sec = end->tv_sec - start->tv_sec;
    diff->tv_usec = end->tv_usec - start->tv_usec;
    if (diff->tv_usec < 0) {
        diff->tv_sec--;
        diff->tv_usec += 1000000;
    }
}
#endif

__global__ void hotspot_kernel(int iteration,
                               const float *power,
                               const float *temp_src,
                               float *temp_dst,
                               int grid_cols,
                               int grid_rows,
                               int border_cols,
                               int border_rows,
                               float Cap,
                               float Rx,
                               float Ry,
                               float Rz,
                               float step) {
    __shared__ float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __shared__ float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __shared__ float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int bx = blockIdx.x;
    int by = blockIdx.y;

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    int small_block_rows = BLOCK_SIZE - iteration * 2;
    int small_block_cols = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx, loadXidx = xidx;
    int index = grid_cols * loadYidx + loadXidx;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    }
    __syncthreads();

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool computed = false;
    for (int i = 0; i < iteration; i++) {
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin, validXmax) &&
            IN_RANGE(ty, validYmin, validYmax)) {
            computed = true;
            temp_t[ty][tx] = temp_on_cuda[ty][tx] + step_div_Cap * (
                power_on_cuda[ty][tx] +
                (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 +
                (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 +
                (amb_temp_const - temp_on_cuda[ty][tx]) * Rz_1);
        }
        __syncthreads();

        if (i == iteration - 1)
            break;
        if (computed)
            temp_on_cuda[ty][tx] = temp_t[ty][tx];

        __syncthreads();
    }

    if (computed) {
        temp_dst[index] = temp_t[ty][tx];
    }
}

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++) {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = fopen(file, "r")) == 0)
        fatal("The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++) {
            if (fgets(str, STR_SIZE, fp) == NULL)
                fatal("Error reading file\n");
            if (feof(fp))
                fatal("not enough lines in file");

            if ((sscanf(str, "%f", &val) != 1))
                fatal("invalid file format");
            vect[i * grid_cols + j] = val;
        }

    fclose(fp);
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows,
                      int borderCols, int borderRows, float *TempCPU, float *PowerCPU) {
    (void)TempCPU;
    (void)PowerCPU;

    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;
    int t, itr;

    int src = 0, dst = 1;

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((unsigned int)blockCols, (unsigned int)blockRows);

#ifdef TIMING
    int num_launches = (total_iterations + num_iterations - 1) / num_iterations;
    cudaEvent_t *start_events = (cudaEvent_t *)malloc(sizeof(cudaEvent_t) * num_launches);
    cudaEvent_t *end_events = (cudaEvent_t *)malloc(sizeof(cudaEvent_t) * num_launches);
    if (!start_events || !end_events)
        fatal("unable to allocate memory");
#endif

    for (t = 0, itr = 0; t < total_iterations; t += num_iterations, itr++) {
        int iter = MIN(num_iterations, total_iterations - t);

#ifdef TIMING
        CUDA_CHECK(cudaEventCreate(&start_events[itr]));
        CUDA_CHECK(cudaEventCreate(&end_events[itr]));
        CUDA_CHECK(cudaEventRecord(start_events[itr], 0));
#endif

        hotspot_kernel<<<grid, block>>>(iter, MatrixPower, MatrixTemp[src], MatrixTemp[dst],
                                        col, row, borderCols, borderRows,
                                        Cap, Rx, Ry, Rz, step);
        CUDA_CHECK(cudaGetLastError());

#ifdef TIMING
        CUDA_CHECK(cudaEventRecord(end_events[itr], 0));
#endif

        src = 1 - src;
        dst = 1 - dst;
    }

#ifdef TIMING
    for (t = 0, itr = 0; t < total_iterations; t += num_iterations, itr++) {
        float ms = 0.0f;
        CUDA_CHECK(cudaEventSynchronize(end_events[itr]));
        CUDA_CHECK(cudaEventElapsedTime(&ms, start_events[itr], end_events[itr]));
        kernel_time += ms;
        CUDA_CHECK(cudaEventDestroy(start_events[itr]));
        CUDA_CHECK(cudaEventDestroy(end_events[itr]));
    }
    free(start_events);
    free(end_events);
#else
    CUDA_CHECK(cudaDeviceSynchronize());
#endif

    return src;
}

void usage(int argc, char **argv) {
    (void)argc;
    fprintf(stderr, "Usage: %s <grid_rows/grid_cols> <pyramid_height> <sim_time> <temp_file> <power_file> <output_file> [-p platform_id] [-d device_id]\n", argv[0]);
    fprintf(stderr, "\t<grid_rows/grid_cols>  - number of rows/cols in the grid (positive integer)\n");
    fprintf(stderr, "\t<pyramid_height> - pyramid heigh(positive integer)\n");
    fprintf(stderr, "\t<sim_time>   - number of iterations\n");
    fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
    fprintf(stderr, "\t<output_file> - name of the output file\n");
    exit(1);
}

int main(int argc, char **argv) {
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

    int size;
    int grid_rows, grid_cols = 0;
    float *FilesavingTemp, *FilesavingPower;
    char *tfile, *pfile, *ofile;

    int total_iterations = 60;
    int pyramid_height = 1;

    if (argc < 7)
        usage(argc, argv);
    if ((grid_rows = atoi(argv[1])) <= 0 ||
        (grid_cols = atoi(argv[1])) <= 0 ||
        (pyramid_height = atoi(argv[2])) <= 0 ||
        (total_iterations = atoi(argv[3])) <= 0)
        usage(argc, argv);

    tfile = argv[4];
    pfile = argv[5];
    ofile = argv[6];
    size = grid_rows * grid_cols;

    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0)
            usage(argc, argv);
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    (void)platform_id_inuse;

    int borderCols = (pyramid_height) * EXPAND_RATE / 2;
    int borderRows = (pyramid_height) * EXPAND_RATE / 2;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height) * EXPAND_RATE;
    int smallBlockRow = BLOCK_SIZE - (pyramid_height) * EXPAND_RATE;
    int blockCols = grid_cols / smallBlockCol + ((grid_cols % smallBlockCol == 0) ? 0 : 1);
    int blockRows = grid_rows / smallBlockRow + ((grid_rows % smallBlockRow == 0) ? 0 : 1);

    FilesavingTemp = (float *)malloc(size * sizeof(float));
    FilesavingPower = (float *)malloc(size * sizeof(float));

    if (!FilesavingPower || !FilesavingTemp)
        fatal("unable to allocate memory");

    readinput(FilesavingTemp, grid_rows, grid_cols, tfile);
    readinput(FilesavingPower, grid_rows, grid_cols, pfile);

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    int device_count = 0;
    CUDA_CHECK(cudaGetDeviceCount(&device_count));

    printf("Platform: NVIDIA CUDA\n");
    printf("num_devices = %d\n", device_count);

    if (device_count <= 0)
        fatal("No CUDA devices found");

    if (device_id_inuse >= device_count) {
        printf("Invalid Device Number\n");
        exit(1);
    }

    CUDA_CHECK(cudaSetDevice(device_id_inuse));

    cudaDeviceProp prop;
    CUDA_CHECK(cudaGetDeviceProperties(&prop, device_id_inuse));
    printf("Device: %s\n", prop.name);
    printf("Use GPU device\n");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    float *MatrixTemp[2];
    float *MatrixPower;

    CUDA_CHECK(cudaMalloc((void **)&MatrixTemp[1], sizeof(float) * size));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_h2d_start, NULL);
#endif

    CUDA_CHECK(cudaMalloc((void **)&MatrixTemp[0], sizeof(float) * size));
    CUDA_CHECK(cudaMemcpy(MatrixTemp[0], FilesavingTemp, sizeof(float) * size, cudaMemcpyHostToDevice));

    CUDA_CHECK(cudaMalloc((void **)&MatrixPower, sizeof(float) * size));
    CUDA_CHECK(cudaMemcpy(MatrixPower, FilesavingPower, sizeof(float) * size, cudaMemcpyHostToDevice));

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_mem_alloc_end, &tv);
    h2d_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int ret = compute_tran_temp(MatrixPower, MatrixTemp, grid_cols, grid_rows, total_iterations,
                                pyramid_height, blockCols, blockRows, borderCols, borderRows,
                                FilesavingTemp, FilesavingPower);

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

    float *MatrixOut = (float *)malloc(sizeof(float) * size);
    if (!MatrixOut)
        fatal("unable to allocate memory");
    CUDA_CHECK(cudaMemcpy(MatrixOut, MatrixTemp[ret], sizeof(float) * size, cudaMemcpyDeviceToHost));

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    writeoutput(MatrixOut, grid_rows, grid_cols, ofile);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    CUDA_CHECK(cudaFree(MatrixTemp[0]));
    CUDA_CHECK(cudaFree(MatrixTemp[1]));
    CUDA_CHECK(cudaFree(MatrixPower));

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    free(MatrixOut);
    free(FilesavingTemp);
    free(FilesavingPower);

    return 0;
}

