#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

#define STR_SIZE 256
#define EXPAND_RATE 2
#define MAX_PD (3.0e6)
#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP 0.5
#define MIN(a, b) ((a) <= (b) ? (a) : (b))
#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

const static float t_chip = 0.0005f;
const static float chip_height = 0.016f;
const static float chip_width = 0.016f;
const static float amb_temp = 80.0f;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static void tvsub(struct timeval *out, const struct timeval *t1, const struct timeval *t0) {
    out->tv_sec = t1->tv_sec - t0->tv_sec;
    out->tv_usec = t1->tv_usec - t0->tv_usec;
    if (out->tv_usec < 0) {
        out->tv_sec--;
        out->tv_usec += 1000000;
    }
}
#endif

static void fatal(const char *s) {
    fprintf(stderr, "Error: %s\n", s);
    exit(1);
}

static void fatal_cuda(cudaError_t error, int line_no) {
    fprintf(stderr, "Error at line %d: %s\n", line_no, cudaGetErrorString(error));
    exit((int)error);
}

#define CUDA_CHECK(call) do { cudaError_t _e = (call); if (_e != cudaSuccess) fatal_cuda(_e, __LINE__); } while (0)

__global__ void hotspot(int iteration,
                        const float *power,
                        const float *temp_src,
                        float *temp_dst,
                        int grid_cols,
                        int grid_rows,
                        int border_cols,
                        int border_rows,
                        float Cap,
                        float Rx,
                        float Ry,
                        float Rz,
                        float step) {
    __shared__ float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __shared__ float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __shared__ float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int bx = blockIdx.x;
    int by = blockIdx.y;

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    int small_block_rows = BLOCK_SIZE - iteration * 2;
    int small_block_cols = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx;
    int loadXidx = xidx;
    int index = grid_cols * loadYidx + loadXidx;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    }
    __syncthreads();

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool computed = false;
    for (int i = 0; i < iteration; i++) {
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin, validXmax) &&
            IN_RANGE(ty, validYmin, validYmax)) {
            computed = true;
            temp_t[ty][tx] = temp_on_cuda[ty][tx] + step_div_Cap * (
                power_on_cuda[ty][tx] +
                (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 +
                (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 +
                (80.0f - temp_on_cuda[ty][tx]) * Rz_1
            );
        }
        __syncthreads();

        if (i == iteration - 1)
            break;
        if (computed)
            temp_on_cuda[ty][tx] = temp_t[ty][tx];

        __syncthreads();
    }

    if (computed) {
        temp_dst[index] = temp_t[ty][tx];
    }
}

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++) {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = fopen(file, "r")) == 0)
        fatal("The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++) {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
                fatal("not enough lines in file");

            if ((sscanf(str, "%f", &val) != 1))
                fatal("invalid file format");
            vect[i * grid_cols + j] = val;
        }

    fclose(fp);
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows,
                      int borderCols, int borderRows, float *TempCPU, float *PowerCPU) {
    (void)TempCPU;
    (void)PowerCPU;

    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;
    int t, itr;

    int src = 0, dst = 1;

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid(blockCols, blockRows);

#ifdef TIMING
    int num_launches = total_iterations / num_iterations + 1;
    cudaEvent_t *start_events = (cudaEvent_t *)malloc(sizeof(cudaEvent_t) * num_launches);
    cudaEvent_t *stop_events = (cudaEvent_t *)malloc(sizeof(cudaEvent_t) * num_launches);
    if (!start_events || !stop_events) fatal("unable to allocate memory");
#endif

    for (t = 0, itr = 0; t < total_iterations; t += num_iterations, itr++) {
        int iter = MIN(num_iterations, total_iterations - t);

#ifdef TIMING
        CUDA_CHECK(cudaEventCreate(&start_events[itr]));
        CUDA_CHECK(cudaEventCreate(&stop_events[itr]));
        CUDA_CHECK(cudaEventRecord(start_events[itr], 0));
#endif

        hotspot<<<grid, block>>>(iter, MatrixPower, MatrixTemp[src], MatrixTemp[dst],
                                 col, row, borderCols, borderRows, Cap, Rx, Ry, Rz, step);
        CUDA_CHECK(cudaGetLastError());

#ifdef TIMING
        CUDA_CHECK(cudaEventRecord(stop_events[itr], 0));
#endif

        src = 1 - src;
        dst = 1 - dst;
    }

    CUDA_CHECK(cudaDeviceSynchronize());

#ifdef TIMING
    for (t = 0, itr = 0; t < total_iterations; t += num_iterations, itr++) {
        float ms = 0.0f;
        CUDA_CHECK(cudaEventElapsedTime(&ms, start_events[itr], stop_events[itr]));
        kernel_time += ms;
        CUDA_CHECK(cudaEventDestroy(start_events[itr]));
        CUDA_CHECK(cudaEventDestroy(stop_events[itr]));
    }
    free(start_events);
    free(stop_events);
#endif

    return src;
}

