    if (cerr != cudaSuccess || num_devices <= 0) {
        printf("Error: Failed to find a platform!\n%s\n", err_code((int)cerr));
        return EXIT_FAILURE;
    }

    printf("num_devices = %d\n", num_devices);
    if (device_id_inuse > num_devices) {
        printf("Invalid Device Number\n");
        return EXIT_FAILURE;
    }

    cerr = cudaSetDevice(device_id_inuse);
    if (cerr != cudaSuccess) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return EXIT_FAILURE;
    }

    output_device_info(device_id_inuse);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    cudaError_t err1 = cudaMalloc((void **)&d_a, sizeof(float) * count);
    cudaError_t err2 = cudaMalloc((void **)&d_b, sizeof(float) * count);
    cudaError_t err3 = cudaMalloc((void **)&d_c, sizeof(float) * count);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
