    if (err1 != cudaSuccess || err2 != cudaSuccess || err3 != cudaSuccess) {
        printf("Error: Failed to allocate device memory!\n");
        exit(1);
    }

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    cerr = cudaMemcpy(d_a, tIn, sizeof(float) * count, cudaMemcpyHostToDevice);
    if (cerr != cudaSuccess) {
        printf("Error: Failed to write tIn to source array!\n%s\n", err_code((int)cerr));
