#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    cerr = cudaMemcpy(d_b, pIn, sizeof(float) * count, cudaMemcpyHostToDevice);
    if (cerr != cudaSuccess) {
        printf("Error: Failed to write pIn to source array!\n%s\n", err_code((int)cerr));
        exit(1);
    }
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
