extern "C" void stopwatch_start(stopwatch *sw){
    if (sw == NULL)
        return;

    memset(&sw->begin, 0, sizeof(struct timeval));
    memset(&sw->end, 0, sizeof(struct timeval));

    gettimeofday(&sw->begin, NULL);
}

extern "C" void stopwatch_stop(stopwatch *sw){
    if (sw == NULL)
        return;

    gettimeofday(&sw->end, NULL);
}

extern "C" double get_interval_by_sec(stopwatch *sw){
    if (sw == NULL)
        return 0;
    return ((double)(sw->end.tv_sec - sw->begin.tv_sec) +
            (double)(sw->end.tv_usec - sw->begin.tv_usec) / 1000000);
}

extern "C" int get_interval_by_usec(stopwatch *sw){
    if (sw == NULL)
        return 0;
    return ((sw->end.tv_sec - sw->begin.tv_sec) * 1000000 +
            (sw->end.tv_usec - sw->begin.tv_usec));
}

extern "C" func_ret_t create_matrix_from_file(float **mp, const char* filename, int *size_p){
    int i, j, size;
    float *m;
    FILE *fp = NULL;

    fp = fopen(filename, "rb");
    if (fp == NULL) {
        return RET_FAILURE;
    }

    fscanf(fp, "%d\n", &size);

    m = (float*) malloc(sizeof(float) * size * size);
    if (m == NULL) {
        fclose(fp);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            fscanf(fp, "%f ", m + i * size + j);
        }
    }

    fclose(fp);

    *size_p = size;
    *mp = m;

    return RET_SUCCESS;
}

extern "C" func_ret_t create_matrix_from_random(float **mp, int size){
    float *l, *u, *m;
    int i, j, k;

    srand(time(NULL));

    l = (float*)malloc(size * size * sizeof(float));
    if (l == NULL)
        return RET_FAILURE;

    u = (float*)malloc(size * size * sizeof(float));
    if (u == NULL) {
        free(l);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            if (i > j) {
                l[i * size + j] = GET_RAND_FP;
            } else if (i == j) {
                l[i * size + j] = 1;
            } else {
                l[i * size + j] = 0;
            }
        }
    }

    for (j = 0; j < size; j++) {
        for (i = 0; i < size; i++) {
            if (i > j) {
                u[j * size + i] = 0;
            } else {
                u[j * size + i] = GET_RAND_FP;
            }
        }
    }

    m = (float*)malloc(size * size * sizeof(float));
    if (m == NULL) {
        free(l);
        free(u);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            for (k = 0; k <= MIN(i, j); k++)
                m[i * size + j] = l[i * size + k] * u[j * size + k];
        }
    }

    free(l);
    free(u);

    *mp = m;

    return RET_SUCCESS;
}

extern "C" void matrix_multiply(float *inputa, float *inputb, float *output, int size){
