extern "C" func_ret_t lud_verify(float *m, float *lu, int matrix_dim){
    int i, j, k;
    float *tmp = (float*)malloc(matrix_dim * matrix_dim * sizeof(float));
    if (tmp == NULL)
        return RET_FAILURE;

    for (i = 0; i < matrix_dim; i++)
        for (j = 0; j < matrix_dim; j++) {
            float sum = 0;
            float l, u;
            for (k = 0; k <= MIN(i, j); k++) {
                if (i == k)
                    l = 1;
                else
                    l = lu[i * matrix_dim + k];
                u = lu[k * matrix_dim + j];
                sum += l * u;
            }
            tmp[i * matrix_dim + j] = sum;
        }

    for (i = 0; i < matrix_dim; i++) {
        for (j = 0; j < matrix_dim; j++) {
            if (fabs(m[i * matrix_dim + j] - tmp[i * matrix_dim + j]) > 0.0001)
                printf("dismatch at (%d, %d): (o)%f (n)%f\n", i, j, m[i * matrix_dim + j], tmp[i * matrix_dim + j]);
        }
    }
    free(tmp);
    return RET_SUCCESS;
}

extern "C" void matrix_duplicate(float *src, float **dst, int matrix_dim) {
    int s = matrix_dim * matrix_dim * (int)sizeof(float);
    float *p = (float *)malloc(s);
    memcpy(p, src, s);
    *dst = p;
}

extern "C" void print_matrix(float *m, int matrix_dim) {
    int i, j;
    for (i = 0; i < matrix_dim; i++) {
        for (j = 0; j < matrix_dim; j++)
            printf("%f ", m[i * matrix_dim + j]);
        printf("\n");
    }
}

extern "C" func_ret_t create_matrix(float **mp, int size){
    float *m;
    int i, j;
    float lamda = -0.001f;
    float *coe;
    float coe_i = 0.0f;

    coe = (float*)malloc(sizeof(float) * (2 * size - 1));
    if (coe == NULL) {
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        coe_i = 10 * exp(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    m = (float*) malloc(sizeof(float) * size * size);
    if (m == NULL) {
        free(coe);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }

    free(coe);

    *mp = m;

    return RET_SUCCESS;
}

