func_ret_t create_matrix(float **mp, int size) {
    float *m;
    int i, j;
    float lamda = -0.001f;
    float *coe;
    float coe_i = 0.0f;

    coe = (float *)malloc((2 * size - 1) * sizeof(float));
    if (coe == NULL) {
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        coe_i = 10.0f * expf(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    m = (float *)malloc(sizeof(float) * size * size);
    if (m == NULL) {
        free(coe);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
