    int num_devices = 0;
    (void)platform_id_inuse;

    cudaError_t cerr = cudaGetDeviceCount(&num_devices);
    if (cerr != cudaSuccess) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return -1;
    }

    printf("num_devices = %d\n", num_devices);

    if (device_id_inuse > num_devices) {
        printf("Invalid Device Number\n");
        return -1;
    }

    if (num_devices <= 0) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return -1;
    }

    if (device_id_inuse >= num_devices)
        device_id_inuse = num_devices - 1;

    cerr = cudaSetDevice(device_id_inuse);
    if (cerr != cudaSuccess) {
        printf("ERROR: clCreateContextFromType(GPU) failed\n");
        return -1;
    }

    printf("Create GPU context\n");
    return 0;
}

static int shutdown()
{
    cudaDeviceReset();
    return 0;
}

static int do_verify = 0;

static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {"platform", 1, NULL, 'p'},
    {"device", 1, NULL, 'd'},
    {0,0,0,0}
};

int main ( int argc, char *argv[] )
{
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
#endif

    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    int matrix_dim = 32;
    int opt, option_index=0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m = NULL, *mm = NULL;
    stopwatch sw;
    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:",
                              long_options, &option_index)) != -1 ) {
        switch(opt){
            case 'i':
                input_file = optarg;
                break;
            case 'v':
                do_verify = 1;
                break;
            case 's':
                matrix_dim = atoi(optarg);
                printf("Generate input matrix internally, size =%lu\n", (unsigned long)matrix_dim);
                break;
            case 'p':
                platform_id_inuse = atoi(optarg);
                break;
            case 'd':
                device_id_inuse = atoi(optarg);
                break;
            case '?':
                fprintf(stderr, "invalid option\n");
                break;
            case ':':
                fprintf(stderr, "missing argument\n");
                break;
            default:
                fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                        argv[0]);
                exit(EXIT_FAILURE);
        }
    }

    if ( (optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    }

    else if (matrix_dim) {
        printf("Creating matrix internally size=%lu\n", (unsigned long)matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%lu\n", (unsigned long)matrix_dim);
            exit(EXIT_FAILURE);
        }
    }

    else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify){
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    if(initialize(platform_id_inuse, device_id_inuse)) return -1;

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;
#endif

    float *d_m = NULL;
    cudaError_t err = cudaMalloc((void**)&d_m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float));
    if(err != cudaSuccess) {
        printf("ERROR: clCreateBuffer d_m (size:%lu) => %d\n",
               (unsigned long)((size_t)matrix_dim * (size_t)matrix_dim), (int)err);
        return -1;
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;
#endif

    stopwatch_start(&sw);

#ifdef TIMING
    {
        cudaEvent_t ev_start, ev_stop;
        cudaEventCreate(&ev_start);
        cudaEventCreate(&ev_stop);
        cudaEventRecord(ev_start, 0);
        err = cudaMemcpy(d_m, m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float), cudaMemcpyHostToDevice);
        cudaEventRecord(ev_stop, 0);
        if(err != cudaSuccess) {
            printf("ERROR: clEnqueueWriteBuffer d_m (size:%lu) => %d\n",
                   (unsigned long)((size_t)matrix_dim * (size_t)matrix_dim), (int)err);
            return -1;
        }
        h2d_time += event_elapsed_ms(ev_start, ev_stop);
        cudaEventDestroy(ev_start);
        cudaEventDestroy(ev_stop);
    }
#else
    err = cudaMemcpy(d_m, m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) {
        printf("ERROR: clEnqueueWriteBuffer d_m (size:%lu) => %d\n",
               (unsigned long)((size_t)matrix_dim * (size_t)matrix_dim), (int)err);
        return -1;
    }
#endif

#ifdef TIMING
    {
        cudaEvent_t ev_start, ev_stop;
        cudaEventCreate(&ev_start);
        cudaEventCreate(&ev_stop);
        cudaEventRecord(ev_start, 0);
        lud_cuda(d_m, matrix_dim);
        cudaEventRecord(ev_stop, 0);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            printf("ERROR: kernel execution failed => %d\n", (int)err);
            return -1;
        }
        kernel_time += event_elapsed_ms(ev_start, ev_stop);
        err = cudaDeviceSynchronize();
        if (err != cudaSuccess) {
            printf("ERROR: kernel execution failed => %d\n", (int)err);
            return -1;
        }
        cudaEventDestroy(ev_start);
        cudaEventDestroy(ev_stop);
    }
#else
