    }
    err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        printf("ERROR: kernel execution failed => %d\n", (int)err);
        return -1;
    }
#endif

#ifdef TIMING
    {
        cudaEvent_t ev_start, ev_stop;
        cudaEventCreate(&ev_start);
        cudaEventCreate(&ev_stop);
        cudaEventRecord(ev_start, 0);
        err = cudaMemcpy(m, d_m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float), cudaMemcpyDeviceToHost);
        cudaEventRecord(ev_stop, 0);
        if(err != cudaSuccess) {
            printf("ERROR: clEnqueueReadBuffer  d_m (size:%lu) => %d\n",
                   (unsigned long)((size_t)matrix_dim * (size_t)matrix_dim), (int)err);
            return -1;
        }
        d2h_time += event_elapsed_ms(ev_start, ev_stop);
        cudaEventDestroy(ev_start);
        cudaEventDestroy(ev_stop);
    }
#else
    err = cudaMemcpy(m, d_m, (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float), cudaMemcpyDeviceToHost);
    if(err != cudaSuccess) {
        printf("ERROR: clEnqueueReadBuffer  d_m (size:%lu) => %d\n",
               (unsigned long)((size_t)matrix_dim * (size_t)matrix_dim), (int)err);
        return -1;
    }
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(d_m);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    if (do_verify){
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim);
        free(mm);
    }

    free(m);

    if(shutdown()) return -1;

    return 0;
}

