#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#ifndef fp
#define fp float
#endif

#ifndef EQUATIONS
#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 18
#endif

extern int device_id_inuse;
extern int platform_id_inuse;

extern long long get_time();

int solver(fp **y,
           fp *x,
           int xmax,
           fp *params,
           fp *com,
           fp *d_initvalu,
           fp *d_finavalu,
           fp *d_params,
           fp *d_com);

static void fatal_cuda(cudaError_t error, int line_no) {
    if (error != cudaSuccess) {
        printf("Error at line %d: %s\n", line_no, cudaGetErrorString(error));
        exit((int)error);
    }
}

int
kernel_gpu_opencl_wrapper( int xmax,
                           int workload,
                           fp ***y,
                           fp **x,
                           fp **params,
                           fp *com)
{
    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long timecopyin = 0;
    long long timekernel = 0;
    long long timecopyout = 0;
    long long timeother;

    time0 = get_time();

    int i;

    cudaError_t error;

    int device_count = 0;
    error = cudaGetDeviceCount(&device_count);
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    printf("Platform: NVIDIA CUDA\n");

    if (device_count <= 0) {
        printf("Error at line %d: no CUDA devices found\n", __LINE__);
        exit(1);
    }

    if (device_id_inuse < 0 || device_id_inuse >= device_count) {
        device_id_inuse = 0;
    }

    error = cudaSetDevice(device_id_inuse);
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    cudaDeviceProp prop;
    error = cudaGetDeviceProperties(&prop, device_id_inuse);
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }
    printf("Device: %s\n", prop.name);

    (void)platform_id_inuse;

    time1 = get_time();

    fp *d_initvalu;
    error = cudaMalloc((void **)&d_initvalu, EQUATIONS * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    fp *d_finavalu;
    error = cudaMalloc((void **)&d_finavalu, EQUATIONS * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    fp *d_params;
    error = cudaMalloc((void **)&d_params, PARAMETERS * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    fp *d_com;
    error = cudaMalloc((void **)&d_com, 3 * sizeof(fp));
    if (error != cudaSuccess) {
        fatal_cuda(error, __LINE__);
    }

    time2 = get_time();

    int status;

    for(i=0; i<workload; i++){

        status = solver( y[i],
                         x[i],
                         xmax,
                         params[i],
                         com,
                         d_initvalu,
                         d_finavalu,
                         d_params,
                         d_com);

        if(status !=0){
            printf("STATUS: %d\n", status);
        }
    }

