#include <cuda_runtime.h>

#define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j)   reference_l[(j) + (i) * BLOCK_SIZE]

__device__ __forceinline__ int maximum_device(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

extern "C" __global__ void
nw_kernel1(int *reference_d,
           int *input_itemsets_d,
           int *output_itemsets_d,
           int cols,
           int penalty,
           int blk,
           int block_width,
           int worksize,
           int offset_r,
           int offset_c) {
    __shared__ int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    __shared__ int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int bx = blockIdx.x;
    int tx = threadIdx.x;

    int base = offset_r * cols + offset_c;

    int b_index_x = bx;
    int b_index_y = blk - 1 - bx;

    int index    = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    int index_n  = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + 1;
    int index_w  = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    int index_nw = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    if (tx == 0) {
        SCORE(tx, 0) = input_itemsets_d[index_nw + tx];
    }

    __syncthreads();

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        REF(ty, tx) = reference_d[index + cols * ty];

    __syncthreads();

    SCORE((tx + 1), 0) = input_itemsets_d[index_w + cols * tx];

    __syncthreads();

    SCORE(0, (tx + 1)) = input_itemsets_d[index_n];

    __syncthreads();

    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (tx <= m) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            SCORE(t_index_y, t_index_x) =
                maximum_device(SCORE((t_index_y - 1), (t_index_x - 1)) + REF((t_index_y - 1), (t_index_x - 1)),
                               SCORE((t_index_y), (t_index_x - 1)) - penalty,
                               SCORE((t_index_y - 1), (t_index_x)) - penalty);
        }
        __syncthreads();
    }

    __syncthreads();

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (tx <= m) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            SCORE(t_index_y, t_index_x) =
                maximum_device(SCORE((t_index_y - 1), (t_index_x - 1)) + REF((t_index_y - 1), (t_index_x - 1)),
                               SCORE((t_index_y), (t_index_x - 1)) - penalty,
                               SCORE((t_index_y - 1), (t_index_x)) - penalty);
        }

        __syncthreads();
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        input_itemsets_d[index + cols * ty] = SCORE((ty + 1), (tx + 1));

    (void)output_itemsets_d;
    (void)block_width;
    (void)worksize;
}

extern "C" __global__ void
nw_kernel2(int *reference_d,
           int *input_itemsets_d,
           int *output_itemsets_d,
           int cols,
           int penalty,
