#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932
#define SCALE_FACTOR 300

static inline void check_cuda(cudaError_t e) {
    if (e != cudaSuccess) {
        printf("\nCUDA error: %s\n", cudaGetErrorString(e));
        exit(1);
    }
}

static inline long long get_time_common() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

static inline double elapsed_time_common(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

namespace naive_impl {

static long M = INT_MAX;
static int A = 1103515245;
static int C = 12345;
static const int threads_per_block = 128;
static int device_id_inuse = 0;
static int platform_id_inuse = 0;

__global__ void particle_kernel(double * arrayX, double * arrayY, double * CDF, double * u,
                                double * xj, double * yj, int Nparticles) {
    int i = blockDim.x * blockIdx.x + threadIdx.x;
    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, int * array3D, int * dimX, int * dimY, int * dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

void addNoise(int * array3D, int * dimX, int * dimY, int * dimZ, int * seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (int)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) +
                                   pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(int * matrix, int posX, int posY, int posZ,
                   int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;

    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) +
                                   pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(int * matrix, int dimX, int dimY, int dimZ, int error, int * newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int * se, int numOnes, double * neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(int * I, int IszX, int IszY, int Nfr, int * seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    int * newMatrix = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    memset(newMatrix, 0, sizeof(int) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);

    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] =
                    newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

double calcLikelihoodSum(int * I, int * ind, int numOnes) {
    double likelihoodSum = 0.0;
    for (int y = 0; y < numOnes; y++) {
        double a = (double)(I[ind[y]] - 100);
        double b = (double)(I[ind[y]] - 228);
        likelihoodSum += (a * a - b * b) / 50.0;
    }
    return likelihoodSum;
}

int particleFilter(int * I, int IszX, int IszY, int Nfr, int * seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    long long start = get_time_common();

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);

    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }

    double * objxy = (double *)malloc(countOnes * 2 * sizeof(double));
    getneighbors(disk, countOnes, objxy, radius);

    long long get_neighbors = get_time_common();
    printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time_common(start, get_neighbors));

    double * weights = (double *)malloc(sizeof(double) * Nparticles);
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = 1 / ((double)(Nparticles));
    }

    long long get_weights = get_time_common();
    printf("TIME TO GET WEIGHTSTOOK: %f\n", elapsed_time_common(get_neighbors, get_weights));

    double * likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double * xj = (double *)malloc(sizeof(double) * Nparticles);
    double * yj = (double *)malloc(sizeof(double) * Nparticles);
    double * CDF = (double *)malloc(sizeof(double) * Nparticles);
    int * ind = (int *)malloc(sizeof(int) * countOnes);
    double * u = (double *)malloc(sizeof(double) * Nparticles);

    double * arrayX_GPU;
    double * arrayY_GPU;
    double * xj_GPU;
    double * yj_GPU;
    double * CDF_GPU;
    double * u_GPU;

    check_cuda(cudaSetDevice(device_id_inuse));
    check_cuda(cudaMalloc((void **)&arrayX_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&arrayY_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&xj_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&yj_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&CDF_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&u_GPU, sizeof(double) * Nparticles));

    for (int x = 0; x < Nparticles; x++) {
        arrayX[x] = xe;
        arrayY[x] = ye;
    }

    for (int k = 1; k < Nfr; k++) {
        long long set_arrays = get_time_common();

        for (int x = 0; x < Nparticles; x++) {
            arrayX[x] = arrayX[x] + 1.0 + 5.0 * randn(seed, x);
            arrayY[x] = arrayY[x] - 2.0 + 2.0 * randn(seed, x);
        }

        long long error = get_time_common();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time_common(set_arrays, error));

        for (int x = 0; x < Nparticles; x++) {
            for (int y = 0; y < countOnes; y++) {
                int indX = (int)roundDouble(arrayX[x]) + (int)objxy[y * 2 + 1];
                int indY = (int)roundDouble(arrayY[x]) + (int)objxy[y * 2];
                ind[y] = abs(indX * IszY * Nfr + indY * Nfr + k);
                if (ind[y] >= max_size)
                    ind[y] = 0;
            }
            likelihood[x] = calcLikelihoodSum(I, ind, countOnes);
            likelihood[x] = likelihood[x] / countOnes;
        }

        long long likelihood_time = get_time_common();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time_common(error, likelihood_time));

        for (int x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] * exp(likelihood[x]);
        }

        long long exponential = get_time_common();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time_common(likelihood_time, exponential));

        double sumWeights = 0;
        for (int x = 0; x < Nparticles; x++) {
            sumWeights += weights[x];
        }

        long long sum_time = get_time_common();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time_common(exponential, sum_time));

        for (int x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] / sumWeights;
        }

        long long normalize = get_time_common();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time_common(sum_time, normalize));

        xe = 0;
        ye = 0;
        for (int x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
        }

        long long move_time = get_time_common();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time_common(normalize, move_time));
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                               pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        CDF[0] = weights[0];
        for (int x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }

        long long cum_sum = get_time_common();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time_common(move_time, cum_sum));

        double u1 = (1 / ((double)(Nparticles))) * randu(seed, 0);
        for (int x = 0; x < Nparticles; x++) {
            u[x] = u1 + x / ((double)(Nparticles));
        }

        long long u_time = get_time_common();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time_common(cum_sum, u_time));

        long long start_copy = get_time_common();
        check_cuda(cudaMemcpy(arrayX_GPU, arrayX, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(arrayY_GPU, arrayY, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(CDF_GPU, CDF, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(u_GPU, u, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        long long end_copy = get_time_common();

        int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
        particle_kernel<<<num_blocks, threads_per_block>>>(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());
        long long start_copy_back = get_time_common();

        check_cuda(cudaMemcpy(yj, yj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(xj, xj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));

        long long end_copy_back = get_time_common();
        printf("SENDING TO GPU TOOK: %lf\n", elapsed_time_common(start_copy, end_copy));
        printf("OPEN_CL EXEC TOOK: %lf\n", elapsed_time_common(end_copy, start_copy_back));
        printf("SENDING BACK FROM GPU TOOK: %lf\n", elapsed_time_common(start_copy_back, end_copy_back));

        long long xyj_time = get_time_common();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time_common(u_time, xyj_time));

        for (int x = 0; x < Nparticles; x++) {
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];
            weights[x] = 1 / ((double)(Nparticles));
        }

        long long reset = get_time_common();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time_common(xyj_time, reset));
    }

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(xj);
    free(yj);
    free(arrayX);
    free(arrayY);
    free(CDF);
    free(u);
    free(ind);

    return 0;
}

int main_impl(int argc, char * argv[]) {
    const char* usage = "naive.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    int * seed = (int *)malloc(sizeof(int) * Nparticles);
    for (int i = 0; i < Nparticles; i++)
        seed[i] = time(0) * i;

    int * I = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    memset(I, 0, sizeof(int) * IszX * IszY * Nfr);

    long long start = get_time_common();
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time_common();
    printf("VIDEO SEQUENCE TOOK %f\n", (float)elapsed_time_common(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time_common();
    printf("PARTICLE FILTER TOOK %f\n", (float)elapsed_time_common(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", (float)elapsed_time_common(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

} // namespace naive_impl

namespace opt_common {

static long M = INT_MAX;
static int A = 1103515245;
static int C = 12345;

template <typename T>
T round_host(T value) {
    int newValue = (int)(value);
    if (value - newValue < (T).5)
        return (T)newValue;
    else
        return (T)(newValue++);
}

template <typename T>
T randu_host(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return (T)fabs(seed[index] / ((double)M));
}

template <typename T>
T randn_host(int * seed, int index) {
    T u = randu_host<T>(seed, index);
    T v = randu_host<T>(seed, index);
    T cosine = cos((T)(2 * PI) * v);
    T rt = (T)(-2) * log(u);
    return sqrt(rt) * cosine;
}

void setIf(int testValue, int newValue, unsigned char * array3D,
           int * dimX, int * dimY, int * dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = (unsigned char)newValue;
            }
        }
    }
}

template <typename T>
void addNoise(unsigned char * array3D, int * dimX, int * dimY, int * dimZ, int * seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn_host<T>(seed, 0));
            }
        }
    }
}

void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) +
                                   pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char * matrix, int posX, int posY, int posZ,
                   int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;

    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) +
                                   pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char * matrix, int dimX, int dimY, int dimZ,
                   int error, unsigned char * newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int * se, int numOnes, int * neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

template <typename T>
void videoSequence(unsigned char * I, int IszX, int IszY, int Nfr, int * seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)round_host<T>((T)(IszY / 2.0));
    int y0 = (int)round_host<T>((T)(IszX / 2.0));
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char * newMatrix = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);

    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] =
                    newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise<T>(I, &IszX, &IszY, &Nfr, seed);
}

template <typename T>
__device__ T dev_round(T value) {
    int newValue = (int)(value);
    if (value - newValue < (T).5)
        return (T)newValue;
    else
        return (T)(newValue++);
}

template <typename T>
__device__ T d_randu(int * seed, int index) {
    int Mloc = INT_MAX;
    int Aloc = 1103515245;
    int Cloc = 12345;
    int num = Aloc * seed[index] + Cloc;
    seed[index] = num % Mloc;
    return (T)fabs(seed[index] / ((double)Mloc));
}

template <typename T>
__device__ T d_randn(int * seed, int index) {
    T pi = (T)3.14159265358979323846;
    T u = d_randu<T>(seed, index);
    T v = d_randu<T>(seed, index);
    T cosine = cos((T)2 * pi * v);
    T rt = (T)-2 * log(u);
    return sqrt(rt) * cosine;
}

template <typename T>
__device__ T calcLikelihoodSum(const unsigned char * I, const int * ind, int numOnes, int index) {
    T likelihoodSum = (T)0.0;
    for (int x = 0; x < numOnes; x++) {
        int idx = ind[index * numOnes + x];
        T a = (T)(I[idx] - 100);
        T b = (T)(I[idx] - 228);
        likelihoodSum += (a * a - b * b) / (T)50.0;
    }
    return likelihoodSum;
}

template <typename T, bool SUBTRACT_SCALE>
__global__ void likelihood_kernel(T * arrayX, T * arrayY, const T * xj, const T * yj,
                                  int * ind, const int * objxy, T * likelihood,
                                  const unsigned char * I, T * weights,
                                  const int Nparticles, const int countOnes,
                                  const int max_size, int k, const int IszY,
                                  const int Nfr, int * seed, T * partial_sums) {
    extern __shared__ unsigned char smem[];
    T * buffer = (T *)smem;

    int block_id = blockIdx.x;
    int thread_id = threadIdx.x;
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int y;
    int indX, indY;

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];
        weights[i] = (T)1 / ((T)Nparticles);

        arrayX[i] = arrayX[i] + (T)1.0 + (T)5.0 * d_randn<T>(seed, i);
        arrayY[i] = arrayY[i] - (T)2.0 + (T)2.0 * d_randn<T>(seed, i);
    }

    if (i < Nparticles) {
        for (y = 0; y < countOnes; y++) {
            indX = (int)dev_round<T>(arrayX[i]) + objxy[y * 2 + 1];
            indY = (int)dev_round<T>(arrayY[i]) + objxy[y * 2];
            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }

        likelihood[i] = calcLikelihoodSum<T>(I, ind, countOnes, i);
        if (SUBTRACT_SCALE)
            likelihood[i] = likelihood[i] / (T)countOnes - (T)SCALE_FACTOR;
        else
            likelihood[i] = likelihood[i] / (T)countOnes;

        weights[i] = weights[i] * exp((double)likelihood[i]);
    }

    buffer[thread_id] = (T)0.0;
    if (i < Nparticles) {
        buffer[thread_id] = weights[i];
    }
    __syncthreads();

    for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
        if ((unsigned int)thread_id < s) {
            buffer[thread_id] += buffer[thread_id + s];
        }
        __syncthreads();
    }

    if (thread_id == 0) {
        partial_sums[block_id] = buffer[0];
    }
}

template <typename T>
__global__ void sum_kernel(T * partial_sums, int num_blocks) {
    if (blockIdx.x == 0 && threadIdx.x == 0) {
        T sum = (T)0;
        for (int x = 0; x < num_blocks; x++) {
            sum += partial_sums[x];
        }
        partial_sums[0] = sum;
    }
}

template <typename T>
__global__ void normalize_weights_kernel(T * weights, int Nparticles, const T * partial_sums) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        weights[i] = weights[i] / partial_sums[0];
    }
}

template <typename T>
__global__ void cdf_u0_kernel(T * CDF, const T * weights, int Nparticles, T * u, int * seed) {
    if (blockIdx.x == 0 && threadIdx.x == 0) {
        if (Nparticles > 0) {
            CDF[0] = weights[0];
            for (int x = 1; x < Nparticles; x++) {
                CDF[x] = weights[x] + CDF[x - 1];
            }
            u[0] = ((T)1 / (T)Nparticles) * d_randu<T>(seed, 0);
        }
    }
}

template <typename T>
__global__ void fill_u_kernel(T * u, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        T u1 = u[0];
        u[i] = u1 + i / ((T)Nparticles);
    }
}

template <typename T>
__global__ void find_index_kernel(const T * arrayX, const T * arrayY, const T * CDF,
                                  const T * u, T * xj, T * yj, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

static int initialize_cuda(int &threads_per_block, int device_id_inuse, int platform_id_inuse) {
    (void)platform_id_inuse;
    int device_count = 0;
    cudaError_t err = cudaGetDeviceCount(&device_count);
    if (err != cudaSuccess || device_count < 1) {
        printf("ERROR: no CUDA devices available\n");
        return -1;
    }

    printf("number of available platforms:%d.\n", 1);
    printf("clGetPlatformInfo: NVIDIA CUDA\n");

    if (device_id_inuse < 0 || device_id_inuse >= device_count)
        device_id_inuse = 0;

    check_cuda(cudaSetDevice(device_id_inuse));

    cudaDeviceProp prop;
    check_cuda(cudaGetDeviceProperties(&prop, device_id_inuse));

    if (prop.maxThreadsPerBlock < threads_per_block)
        threads_per_block = prop.maxThreadsPerBlock;

    return 0;
}

template <typename T, bool SUBTRACT_SCALE>
int particleFilter(unsigned char * I, int IszX, int IszY, int Nfr,
                   int * seed, int Nparticles, int &threads_per_block,
                   int device_id_inuse, int platform_id_inuse) {
    int max_size = IszX * IszY * Nfr;

    T xe = round_host<T>((T)(IszY / 2.0));
    T ye = round_host<T>((T)(IszX / 2.0));

    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)calloc(diameter * diameter, sizeof(int));
    strelDisk(disk, radius);

    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }

    int * objxy = (int *)calloc(countOnes * 2, sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    T * weights = (T *)calloc(Nparticles, sizeof(T));
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = (T)1 / ((T)Nparticles);
    }

    if (initialize_cuda(threads_per_block, device_id_inuse, platform_id_inuse))
        return -1;

    T * likelihood = (T *)calloc(Nparticles + 1, sizeof(T));
    T * arrayX = (T *)calloc(Nparticles, sizeof(T));
    T * arrayY = (T *)calloc(Nparticles, sizeof(T));
    T * xj = (T *)calloc(Nparticles, sizeof(T));
    T * yj = (T *)calloc(Nparticles, sizeof(T));
    T * CDF = (T *)calloc(Nparticles, sizeof(T));
    int * ind = (int *)calloc(countOnes, sizeof(int));
    T * u = (T *)calloc(Nparticles, sizeof(T));

    T * arrayX_GPU = NULL;
    T * arrayY_GPU = NULL;
    T * xj_GPU = NULL;
    T * yj_GPU = NULL;
    T * CDF_GPU = NULL;
    T * likelihood_GPU = NULL;
    unsigned char * I_GPU = NULL;
    T * weights_GPU = NULL;
    int * objxy_GPU = NULL;
    int * ind_GPU = NULL;
    T * u_GPU = NULL;
    int * seed_GPU = NULL;
    T * partial_sums_GPU = NULL;

    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
    if (num_blocks < 1) num_blocks = 1;

    check_cuda(cudaMalloc((void **)&arrayX_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&arrayY_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&xj_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&yj_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&CDF_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&u_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&likelihood_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&weights_GPU, sizeof(T) * Nparticles));
    check_cuda(cudaMalloc((void **)&I_GPU, sizeof(unsigned char) * IszX * IszY * Nfr));
    check_cuda(cudaMalloc((void **)&objxy_GPU, sizeof(int) * 2 * countOnes));
    check_cuda(cudaMalloc((void **)&ind_GPU, sizeof(int) * countOnes * Nparticles));
    check_cuda(cudaMalloc((void **)&seed_GPU, sizeof(int) * Nparticles));
    check_cuda(cudaMalloc((void **)&partial_sums_GPU, sizeof(T) * num_blocks));

    for (int x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time_common();
    check_cuda(cudaMemcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(objxy_GPU, objxy, sizeof(int) * 2 * countOnes, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(weights_GPU, weights, sizeof(T) * Nparticles, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(xj_GPU, xj, sizeof(T) * Nparticles, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(yj_GPU, yj, sizeof(T) * Nparticles, cudaMemcpyHostToDevice));
    check_cuda(cudaMemcpy(seed_GPU, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice));
    long long send_end = get_time_common();

    printf("TIME TO SEND TO GPU: %f\n", elapsed_time_common(send_start, send_end));
    printf("threads_per_block=%d \n", threads_per_block);

    for (int k = 1; k < Nfr; k++) {
        likelihood_kernel<T, SUBTRACT_SCALE>
            <<<num_blocks, threads_per_block, threads_per_block * sizeof(T)>>>(
                arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, ind_GPU, objxy_GPU,
                likelihood_GPU, I_GPU, u_GPU, weights_GPU, Nparticles, countOnes,
                max_size, k, IszY, Nfr, seed_GPU, partial_sums_GPU);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        sum_kernel<T><<<1, 1>>>(partial_sums_GPU, num_blocks);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        normalize_weights_kernel<T><<<num_blocks, threads_per_block>>>(weights_GPU, Nparticles, partial_sums_GPU);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        cdf_u0_kernel<T><<<1, 1>>>(CDF_GPU, weights_GPU, Nparticles, u_GPU, seed_GPU);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        fill_u_kernel<T><<<num_blocks, threads_per_block>>>(u_GPU, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());

        check_cuda(cudaMemcpy(arrayX, arrayX_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(arrayY, arrayY_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(weights, weights_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));

        T total = (T)0.0;
        xe = (T)0;
        ye = (T)0;
        for (int x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
            total += weights[x];
        }

        printf("total weight: %lf\n", (double)total);
        printf("XE: %lf\n", (double)xe);
        printf("YE: %lf\n", (double)ye);
        T distance = sqrt(pow((double)(xe - (int)round_host<T>((T)(IszY / 2.0))), 2) +
                          pow((double)(ye - (int)round_host<T>((T)(IszX / 2.0))), 2));
        printf("%lf\n", (double)distance);

        find_index_kernel<T><<<num_blocks, threads_per_block>>>(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());
    }

    long long back_time = get_time_common();

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(likelihood_GPU);
    cudaFree(I_GPU);
    cudaFree(objxy_GPU);
    cudaFree(ind_GPU);
    cudaFree(seed_GPU);
    cudaFree(partial_sums_GPU);

    long long free_time = get_time_common();

    check_cuda(cudaMemcpy(arrayX, arrayX_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayX_time = get_time_common();
    check_cuda(cudaMemcpy(arrayY, arrayY_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
    long long arrayY_time = get_time_common();
    check_cuda(cudaMemcpy(weights, weights_GPU, sizeof(T) * Nparticles, cudaMemcpyDeviceToHost));
    long long back_end_time = get_time_common();

    printf("GPU Execution: %lf\n", elapsed_time_common(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time_common(back_time, free_time));
    printf("SEND TO SEND BACK: %lf\n", elapsed_time_common(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time_common(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time_common(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time_common(arrayY_time, back_end_time));

    xe = (T)0;
    ye = (T)0;
    for (int x = 0; x < Nparticles; x++) {
        xe += arrayX[x] * weights[x];
        ye += arrayY[x] * weights[x];
    }
    T distance = sqrt(pow((double)(xe - (int)round_host<T>((T)(IszY / 2.0))), 2) +
                      pow((double)(ye - (int)round_host<T>((T)(IszX / 2.0))), 2));

    FILE * fid = fopen("output.txt", "w+");
    if (fid == NULL) {
        printf("The file was not opened for writing\n");
        return -1;
    }
    fprintf(fid, "XE: %lf\n", (double)xe);
    fprintf(fid, "YE: %lf\n", (double)ye);
    fprintf(fid, "distance: %lf\n", (double)distance);
    fclose(fid);

    cudaFree(weights_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
    free(weights);
    free(objxy);
    free(disk);

    return 0;
}

