#define PI 3.1415926535897932
#define BLOCK_X 16
#define BLOCK_Y 16

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

const int threads_per_block = 128;

int device_id_inuse = 0;
int platform_id_inuse = 0;

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

