            kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            }
            else {
                mul = mul * NUMBER_THREADS;
                blocks2_x = blocks2_work_size / NUMBER_THREADS;
