        gettimeofday(&tv_kernel_start, NULL);
#endif
        srad2_kernel<<<blocks_x, NUMBER_THREADS>>>(lambda,
                                                   Nr,
                                                   Nc,
                                                   Ne,
                                                   d_iN,
                                                   d_iS,
                                                   d_jE,
                                                   d_jW,
                                                   d_dN,
                                                   d_dS,
                                                   d_dE,
                                                   d_dW,
                                                   d_c,
                                                   d_I);
