#include <cuda_runtime.h>

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

__global__ void memset_kernel_cuda(char *mem_d, short val, int number_bytes) {
  const int thread_id = blockIdx.x * blockDim.x + threadIdx.x;
  if (thread_id < number_bytes) {
    mem_d[thread_id] = (char)val;
  }
}

__global__ void pgain_kernel_cuda(
    const Point_Struct *p,
    const float *coord_d,
    float *work_mem_d,
    const int *center_table_d,
    char *switch_membership_d,
    int num,
    int dim,
    long x,
    int K) {
  const int thread_id = blockIdx.x * blockDim.x + threadIdx.x;
  const int local_id = threadIdx.x;

  extern __shared__ float coord_s[];

  if (local_id == 0) {
    for (int i = 0; i < dim; i++) {
      coord_s[i] = coord_d[(long)i * num + x];
    }
  }
  __syncthreads();

  if (thread_id < num) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float diff = coord_d[(long)i * num + thread_id] - coord_s[i];
      x_cost += diff * diff;
    }
    x_cost = x_cost * p[thread_id].weight;

    float current_cost = p[thread_id].cost;
    long base = (long)thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership_d[thread_id] = '1';
      work_mem_d[base + K] = x_cost - current_cost;
    } else {
      long assign = p[thread_id].assign;
      work_mem_d[base + center_table_d[assign]] += current_cost - x_cost;
    }
  }
}

void launch_memset_kernel(char *mem_d, short val, int number_bytes, int threads) {
  int blocks = (number_bytes + threads - 1) / threads;
  memset_kernel_cuda<<<blocks, threads>>>(mem_d, val, number_bytes);
}

void launch_pgain_kernel(
    const Point_Struct *p,
    const float *coord_d,
    float *work_mem_d,
    const int *center_table_d,
    char *switch_membership_d,
    int num,
    int dim,
    long x,
    int K,
    int threads) {
  int blocks = (num + threads - 1) / threads;
  size_t smem = (size_t)dim * sizeof(float);
  pgain_kernel_cuda<<<blocks, threads, smem>>>(
      p, coord_d, work_mem_d, center_table_d, switch_membership_d, num, dim, x, K);
}

