#endif
#ifdef PROFILE_TMP
    double t8 = gettime();
    *cpu_gpu_memcpy_local += t8 - t7;
#endif

    size_t smSize = (size_t)dim * sizeof(float);
#ifdef PROFILE_TMP
    double t9 = gettime();
#endif
#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif
    cudaThrow(cudaMemset(switch_membership_d, 0, (size_t)num * sizeof(char)), "cudaMemset switch_membership_d");
    cudaThrow(cudaMemset(work_mem_d, 0, (size_t)(K + 1) * num * sizeof(float)), "cudaMemset work_mem_d");

    int blocks = (num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
    pgain_kernel<<<blocks, THREADS_PER_BLOCK, smSize>>>(p_d, coord_d, work_mem_d,
                                                        center_table_d, switch_membership_d,
                                                        num, dim, x, K);
    cudaThrow(cudaGetLastError(), "pgain_kernel launch");
    cudaThrow(cudaDeviceSynchronize(), "pgain_kernel sync");
#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
#ifdef PROFILE_TMP
    double t10 = gettime();
    *kernel_local += t10 - t9;
#endif

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    cudaThrow(cudaMemcpy(switch_membership_local, switch_membership_d, (size_t)num * sizeof(char), cudaMemcpyDeviceToHost), "cudaMemcpy switch_membership back");
    cudaThrow(cudaMemcpy(work_mem_h, work_mem_d, (size_t)(K + 1) * num * sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy work_mem back");
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
#ifdef PROFILE_TMP
    double t11 = gettime();
    *memcpy_back_local += t11 - t10;
#endif

    int numclose = 0;
    gl_cost = z;

    for (int i = 0; i < num; i++) {
      if (is_center_local[i]) {
        float low = z;
        for (int j = 0; j < num; j++)
          low += work_mem_h[j * (K + 1) + center_table_local[i]];

        gl_lower[center_table_local[i]] = low;

        if (low > 0) {
          numclose++;
          work_mem_h[i * (K + 1) + K] -= low;
        }
      }
      gl_cost += work_mem_h[i * (K + 1) + K];
    }

    if (gl_cost < 0) {
      for (int i = 0; i < num; i++) {
        bool close_center = gl_lower[center_table_local[points->p[i].assign]] > 0;
        if ((switch_membership_local[i] == '1') || close_center) {
          points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
          points->p[i].assign = x;
        }
      }

      for (int i = 0; i < num; i++) {
        if (is_center_local[i] && gl_lower[center_table_local[i]] > 0)
          is_center_local[i] = false;
      }

      is_center_local[x] = true;
      *numcenters = *numcenters + 1 - numclose;
    } else
      gl_cost = 0;

#ifdef PROFILE_TMP
    double t12 = gettime();
    *serial_local += t12 - t11;
#endif
    c++;
  } catch (string msg) {
    printf("--cambine:%s\n", msg.c_str());
    freeDevMem();
    _clRelease();
    exit(-1);
  } catch (...) {
    printf("--cambine: unknow reasons in pgain\n");
  }

  return -gl_cost;
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t *barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  long bsize = points->num / nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if (pid == nproc - 1) k2 = points->num;
  static float totalcost;

  static bool open = false;
  static float *costs;
  static int i;

#ifdef ENABLE_THREADS
  static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
  static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
#endif

#ifdef PRINTINFO
  if (pid == 0) {
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for (int k = (int)k1; k < (int)k2; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  if (pid == 0) {
    *kcenter = 1;
    costs = (float *)malloc(sizeof(float) * nproc);
  }

  if (pid != 0) {
    while (1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while (!open) pthread_cond_wait(&cond, &mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if (i >= points->num) break;
      for (int k = (int)k1; k < (int)k2; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
#ifdef ENABLE_THREADS
      pthread_barrier_wait(barrier);
      pthread_barrier_wait(barrier);
#endif
    }
  } else {
    for (i = 1; i < points->num; i++) {
      bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
      if (to_open) {
        (*kcenter)++;
#ifdef ENABLE_THREADS
        pthread_mutex_lock(&mutex);
#endif
        open = true;
#ifdef ENABLE_THREADS
        pthread_mutex_unlock(&mutex);
        pthread_cond_broadcast(&cond);
#endif
        for (int k = (int)k1; k < (int)k2; k++) {
          float distance = dist(points->p[i], points->p[k], points->dim);
          if (distance * points->p[k].weight < points->p[k].cost) {
            points->p[k].cost = distance * points->p[k].weight;
            points->p[k].assign = i;
          }
        }
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
        open = false;
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
      }
    }
#ifdef ENABLE_THREADS
    pthread_mutex_lock(&mutex);
#endif
    open = true;
#ifdef ENABLE_THREADS
    pthread_mutex_unlock(&mutex);
    pthread_cond_broadcast(&cond);
#endif
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  open = false;
  float mytotal = 0;
  for (int k = (int)k1; k < (int)k2; k++) {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if (pid == 0) {
    totalcost = z * (*kcenter);
    for (int i = 0; i < nproc; i++) {
      totalcost += costs[i];
    }
    free(costs);
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

#ifdef PRINTINFO
  if (pid == 0) {
    fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
            *kcenter, totalcost);
    fprintf(stderr, "Distance Cost %lf\n", totalcost - z * (*kcenter));
  }
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  if (pid == 0) {
    time_speedy += t2 - t1;
  }
#endif
  return (totalcost);
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e,
          int pid, pthread_barrier_t *barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;

    if (pid == 0) {
      intshuffle(feasible, numfeasible);
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }
    cost -= change;
#ifdef PRINTINFO
    if (pid == 0) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n",
              *k, cost, cost - z * (*k));
    }
#endif
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return (cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t *barrier) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc((size_t)numfeasible * sizeof(int));

  float *accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < (int)k2; i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float *)malloc((size_t)points->num * sizeof(float));
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < (int)k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }
  free(accumweight);
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal,
               int pid, pthread_barrier_t *barrier) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static float *hizs;

  if (pid == 0) hizs = (float *)calloc((size_t)nproc, sizeof(float));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num / nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if (pid == nproc - 1) k2 = points->num;

#ifdef PRINTINFO
  if (pid == 0) {
    printf("Starting Kmedian procedure\n");
    printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
  }
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  float myhiz = 0;
  for (long kk = k1; kk < k2; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hizs[pid] = myhiz;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for (int i = 0; i < nproc; i++) {
    hiz += hizs[i];
  }

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = k1; kk < k2; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if (pid == 0) {
      free(hizs);
      *kfinal = k;
    }
    return cost;
  }

  if (pid == 0) shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);
#ifdef PRINTINFO
  if (pid == 0)
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n", pid, cost, k);
#endif
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if (pid == 0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n", pid, cost, k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    if (pid == 0) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    if (pid == 0) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if (pid == 0) {
    numfeasible = selectfeasible_fast(points, &feasible, (int)kmin, pid, barrier);
    for (int i = 0; i < points->num; i++) {
      is_center[points->p[i].assign] = true;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  while (1) {
#ifdef PRINTINFO
    if (pid == 0) {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.1f, pid, barrier);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      if (pid == 0) {
        printf("Trying a more accurate local search...\n");
      }
#endif
      cost = pFL(points, feasible, numfeasible,
                 z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.001f, pid, barrier);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }

  if (pid == 0) {
    free(feasible);
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;

      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
            points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc((size_t)points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, (size_t)points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void *localSearchSub(void *arg_) {
  pkmedian_arg_t *arg = (pkmedian_arg_t *)arg_;
  pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
  return NULL;
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  pthread_barrier_t barrier;
#ifdef ENABLE_THREADS
  pthread_barrier_init(&barrier, NULL, nproc);
#endif
  pthread_t *threads = new pthread_t[nproc];
  pkmedian_arg_t *arg = new pkmedian_arg_t[nproc];

  for (int i = 0; i < nproc; i++) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;

    arg[i].barrier = &barrier;
#ifdef ENABLE_THREADS
    pthread_create(threads + i, NULL, localSearchSub, (void *)&arg[i]);
#else
    localSearchSub(&arg[0]);
#endif
  }

  for (int i = 0; i < nproc; i++) {
#ifdef ENABLE_THREADS
    pthread_join(threads[i], NULL);
#endif
  }

  delete[] threads;
  delete[] arg;
#ifdef ENABLE_THREADS
  pthread_barrier_destroy(&barrier);
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), (size_t)centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
}

void streamCluster(PStream *stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char *outfile) {
  float *block = (float *)malloc((size_t)chunksize * dim * sizeof(float));
  float *centerBlock = (float *)malloc((size_t)centersize * dim * sizeof(float));
  long *centerIDs = (long *)malloc((size_t)centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc((size_t)chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc((size_t)centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, (int)chunksize);
    fprintf(stderr, "read %lu points\n", numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char *)malloc((size_t)points.num * sizeof(char));
    is_center = (bool *)calloc((size_t)points.num, sizeof(bool));
    center_table = (int *)malloc((size_t)points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (char *)malloc((size_t)centers.num * sizeof(char));
  is_center = (bool *)calloc((size_t)centers.num, sizeof(bool));
  center_table = (int *)malloc((size_t)centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 11) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "  platform:    Platform id\n");
    fprintf(stderr, "  device:      Device id\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);
  _clCmdParams(argc, argv);

#ifdef TIMING
  gettimeofday(&tv_total_start, NULL);
#endif
  try {
    _clInit(platform_id, device_id);
  } catch (std::string msg) {
    std::cout << "exception caught in main function->" << msg << std::endl;
    return -1;
  }
#ifdef TIMING
  gettimeofday(&tv_init_end, NULL);
  tvsub(&tv_init_end, &tv_total_start, &tv);
  init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  srand48(SEED);
  PStream *stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
#ifdef PROFILE_TMP
  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  time_FL = 0.0;
  cnt_speedy = 0;
#endif
  std::cout << "before sc" << std::endl;
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
  std::cout << "after sc" << std::endl;
#ifdef PROFILE_TMP
  gpu_free = gettime();
#endif
#ifdef TIMING
  gettimeofday(&tv_close_start, NULL);
#endif

  freeDevMem();
#ifdef PROFILE_TMP
  gpu_free = gettime() - gpu_free;
#endif
  _clRelease();
#ifdef TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  printf("time = %lf\n", t2 - t1);
#endif

  delete stream;

#ifdef TIMING
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

  printf("Init: %f\n", init_time);
  printf("MemAlloc: %f\n", mem_alloc_time);
  printf("HtoD: %f\n", h2d_time);
  printf("Exec: %f\n", kernel_time);
  printf("DtoH: %f\n", d2h_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

#ifdef PROFILE_TMP
  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time FL = %lf\n", time_FL);
  printf("time localSearch = %lf\n", time_local_search);
  printf("\n");
  printf("====GPU Timing info====\n");
  printf("time serial = %lf\n", serial);
  printf("time CPU to GPU memory copy = %lf\n", cpu_gpu_memcpy);
  printf("time GPU to CPU memory copy back = %lf\n", memcpy_back);
  printf("time GPU malloc = %lf\n", gpu_malloc);
  printf("time GPU free = %lf\n", gpu_free);
  printf("time kernel = %lf\n", kernel);

  FILE *fp = fopen("PD.txt", "w");
  fprintf(fp, "%lf, %lf, %lf, %lf, %lf, %lf, %lf, %lf, %lf\n",
          time_FL, cpu_gpu_memcpy, memcpy_back, kernel, gpu_malloc, gpu_free, 0.0);
  fclose(fp);
#endif
  _clStatistics();
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;
  return 0;
}
